def _replace_prompt_argument_sentinels(value: Any, sentinels: dict[str, str]) -> Any:
    if isinstance(value, str):
        redacted = value
        for name, sentinel in sentinels.items():
            redacted = redacted.replace(sentinel, f"<argument:{name}>")
        return redacted
    if isinstance(value, dict):
        return {key: _replace_prompt_argument_sentinels(item, sentinels) for key, item in value.items()}
    if isinstance(value, list):
        return [_replace_prompt_argument_sentinels(item, sentinels) for item in value]
    return value


def _mcp_prompt_templates_payload(list_prompts_payload: list[dict[str, Any]]) -> dict[str, dict[str, Any]]:
    """Return prompt templates with synthetic argument values redacted to placeholders."""

    async def collect() -> dict[str, dict[str, Any]]:
        templates: dict[str, dict[str, Any]] = {}
        for prompt in list_prompts_payload:
            name = str(prompt.get("name", ""))
            arguments = prompt.get("arguments", []) if isinstance(prompt.get("arguments"), list) else []
            sentinels = {
                str(argument.get("name", "")): f"__MCP_SURFACE_ARGUMENT_{name}_{argument.get('name', '')}__"
                for argument in arguments
                if isinstance(argument, dict) and str(argument.get("name", ""))
            }
            result = await mcp.get_prompt(name, sentinels)
            templates[name] = _replace_prompt_argument_sentinels(_mcp_model_dump(result), sentinels)
        return templates

    return _run_mcp_metadata_collector(collect)


def _public_docs_mentions(names: Iterable[str]) -> dict[str, dict[str, bool]]:
    root = Path(__file__).resolve().parents[1]
    doc_paths = [root / "README.md", root / "docs" / "tool-catalog-integrity.md"]
    docs: dict[str, str] = {}
    for path in doc_paths:
        try:
            docs[path.name if path.name == "README.md" else f"docs/{path.name}"] = path.read_text(encoding="utf-8")
        except OSError:
            docs[path.name] = ""
    return {
        name: {doc: name in text for doc, text in docs.items()}
        for name in names
    }


def _public_discovery_surface_payload() -> dict[str, Any]:
    manifest = _mcp_server_manifest_payload()
    capabilities = manifest.get("capabilities", {}) if isinstance(manifest.get("capabilities"), dict) else {}
    prompt_names = [str(name) for name in capabilities.get("prompts", []) if isinstance(name, str)]
    resources = capabilities.get("resources", []) if isinstance(capabilities.get("resources"), list) else []
    resource_keys = [
        str(resource.get("uri_template") or resource.get("uri") or resource.get("name", ""))
        for resource in resources
        if isinstance(resource, dict)
    ]
    prompt_docs = _public_docs_mentions(prompt_names)
    resource_docs = _public_docs_mentions(resource_keys)
    return {
        "prompts": [
            {"name": name, "documented": prompt_docs.get(name, {})}
            for name in sorted(prompt_names)
        ],
        "resources": [
            {
                **json.loads(json.dumps(resource, sort_keys=True, ensure_ascii=True, default=str)),
                "documented": resource_docs.get(
                    str(resource.get("uri_template") or resource.get("uri") or resource.get("name", "")),
                    {},
                ),
            }
            for resource in sorted(
                [resource for resource in resources if isinstance(resource, dict)],
                key=lambda item: str(item.get("uri_template") or item.get("uri") or item.get("name", "")),
            )
        ],
    }


def _current_tool_catalog_baseline() -> dict[str, Any]:
    prompts = _mcp_list_prompts_payload()
    return build_tool_catalog_baseline(
        _mcp_list_tools_payload(),
        _tool_annotation_manifest(),
        all_tool_output_contracts(),
        list_prompts_payload=prompts,
        prompt_templates=_mcp_prompt_templates_payload(prompts),
        list_resources_payload=_mcp_list_resources_payload(),
        list_resource_templates_payload=_mcp_list_resource_templates_payload(),
        public_discovery=_public_discovery_surface_payload(),
    )


def _tool_catalog_integrity_impl(include_tools: bool = False) -> dict[str, Any]:
    current = _current_tool_catalog_baseline()
    try:
        baseline = load_tool_catalog_baseline(TOOL_CATALOG_BASELINE_FILE)
        baseline_error = ""
    except FileNotFoundError:
        baseline = None
        baseline_error = "missing"
    except (json.JSONDecodeError, OSError, TypeError, ValueError) as exc:
        baseline = None
        baseline_error = f"{type(exc).__name__}: {exc}"
    return integrity_report(
        baseline=baseline,
        current=current,
        baseline_error=baseline_error,
        include_tools=include_tools,
    )


def _tool_catalog_integrity_summary() -> dict[str, Any]:
    try:
        report = _tool_catalog_integrity_impl(include_tools=False)
    except Exception as exc:  # pragma: no cover - defensive report hardening
        return {
            "schema": "tool_catalog_integrity_summary.v1",
            "ok": False,
            "status": "unavailable",
            "error": type(exc).__name__,
            "baseline_path": TOOL_CATALOG_BASELINE_PUBLIC_PATH,
            "contains_secrets": False,
            "contains_repository_contents": False,
        }
    drift = report.get("drift", {}) if isinstance(report.get("drift"), dict) else {}
    lint = report.get("lint", {}) if isinstance(report.get("lint"), dict) else {}
    baseline = report.get("baseline", {}) if isinstance(report.get("baseline"), dict) else {}
    current = report.get("current", {}) if isinstance(report.get("current"), dict) else {}
    return {
        "schema": "tool_catalog_integrity_summary.v1",
        "ok": bool(report.get("ok")),
        "status": str(report.get("status", "")),
        "baseline_path": TOOL_CATALOG_BASELINE_PUBLIC_PATH,
        "baseline_digest": str(baseline.get("whole_catalog_digest", "")),
        "current_digest": str(current.get("whole_catalog_digest", "")),
        "tool_count": int(current.get("tool_count", 0) or 0),
        "prompt_count": int(current.get("prompt_count", 0) or 0),
        "resource_count": int(current.get("resource_count", 0) or 0),
        "public_discovery_count": int(current.get("public_discovery_count", 0) or 0),
        "drift": drift.get("summary", {"added": 0, "removed": 0, "changed": 0}),
        "lint": {
            "advisory_only": True,
            "status": str(lint.get("status", "")),
            "finding_count": int(lint.get("finding_count", 0) or 0),
            "by_type": lint.get("by_type", {}),
        },
        "contains_secrets": False,
        "contains_repository_contents": False,
    }


@mcp.tool()
def tool_catalog_integrity(include_tools: bool = False) -> dict[str, Any]:
    """Compare the live public MCP tool catalog with the checked-in digest baseline."""
    return _tool_catalog_integrity_impl(include_tools=include_tools)


@mcp.tool()
def repo_info() -> dict[str, Any]:
    """Read-only capability probe: repo/git/docker state, branch/head, and server limits."""
    _ensure_repo_path_exists()

    info: dict[str, Any] = {
        "repo_path": str(REPO_PATH),
        "repo_exists": REPO_PATH.exists(),
        "is_git_repo": _is_git_repo(),
        "allow_mutations": ALLOW_MUTATIONS,
        "transport": MCP_TRANSPORT,
        "max_read_bytes": MAX_READ_BYTES,
        "max_output_chars": MAX_OUTPUT_CHARS,
        "docker": _docker_cli_status(),
    }

    if info["is_git_repo"]:
        info["current_branch"] = _git("branch", "--show-current").stdout.strip()
        info["head"] = _git("rev-parse", "HEAD").stdout.strip()
        status = _git("status", "--porcelain").stdout.strip()
        info["dirty"] = bool(status)

    return info


_SAMPLING_SECRET_PATH_RE = re.compile(
    r"(^|/)(?:\.env(?:\.|$)|id_(?:rsa|dsa|ecdsa|ed25519)(?:\.|$)|"
    r"[^/]*\.(?:pem|key|p12|pfx)$|(?:secrets?|credentials?)(?:\.|/|$))",
    re.IGNORECASE,
)
_SAMPLING_PRIVATE_KEY_BLOCK_RE = re.compile(
    r"-----BEGIN [A-Z0-9 ]*PRIVATE KEY-----.*?-----END [A-Z0-9 ]*PRIVATE KEY-----",
    re.IGNORECASE | re.DOTALL,
)
_SAMPLING_HARD_DENIED_USE_CASES = (
    "mutation",
    "write",
    "patch",
    "apply",
    "delete",
    "release_approval",
    "release_readiness_decision",
    "security_conclusion",
    "secret_extraction",
    "credential_handling",
)


def _sampling_allowed_use_cases() -> set[str]:
    values = {
        item.strip().lower().replace("-", "_")
        for item in str(MCP_SAMPLING_ALLOWED_USE_CASES_RAW or "").split(",")
        if item.strip()
    }
    return values or {"summary", "classification", "workflow_selection"}


def _sampling_model_hints() -> list[str]:
    return [
        item.strip()
        for item in str(MCP_SAMPLING_MODEL_HINTS_RAW or "").split(",")
        if item.strip()
    ][:5]


def _sampling_estimated_tokens(text: str) -> int:
    return max(1, math.ceil(len(text) / 4)) if text else 0


def _sampling_digest_text(text: str) -> dict[str, str]:
    return _sha256_digest(text.encode("utf-8", errors="replace"))


def _sampling_redact_text(text: str) -> tuple[str, list[str]]:
    redactions: list[str] = []

    def _record(code: str) -> str:
        if code not in redactions:
            redactions.append(code)
        return f"<redacted:{code}>"

    redacted = _SAMPLING_PRIVATE_KEY_BLOCK_RE.sub(
        lambda _match: _record("private_key_block"), text
    )
    redacted = SENSITIVE_AUDIT_VALUE_RE.sub(
        lambda _match: _record("secret_value"), redacted
    )
    redacted = ABSOLUTE_PATH_VALUE_RE.sub(
        lambda _match: _record("absolute_path"), redacted
    )
    return redacted, redactions


def _sampling_default_paths(max_paths: int) -> list[str]:
    candidates = ["README.md", "AGENTS.md", "pyproject.toml", "docs/index.md"]
    paths: list[str] = []
    for rel in candidates:
        try:
            if _resolve_repo_path(rel).is_file():
                paths.append(rel)
        except Exception:
            continue
        if len(paths) >= max_paths:
            break
    return paths


def _sampling_effective_budget(
    *,
    max_paths: int | None,
    max_bytes: int | None,
    max_context_tokens: int | None,
    max_tokens: int | None,
) -> dict[str, Any]:
    requested = {
        "max_paths": max_paths,
        "max_bytes": max_bytes,
        "max_context_tokens": max_context_tokens,
        "max_output_tokens": max_tokens,
    }
    effective = {
        "max_paths": min(
            MCP_SAMPLING_MAX_PATHS,
            max(1, int(max_paths)) if max_paths is not None else MCP_SAMPLING_MAX_PATHS,
        ),
        "max_bytes": min(
            MCP_SAMPLING_MAX_BYTES,
            max(1, int(max_bytes)) if max_bytes is not None else MCP_SAMPLING_MAX_BYTES,
        ),
        "max_context_tokens": min(
            MCP_SAMPLING_MAX_CONTEXT_TOKENS,
            max(1, int(max_context_tokens))
            if max_context_tokens is not None
            else MCP_SAMPLING_MAX_CONTEXT_TOKENS,
        ),
        "max_output_tokens": min(
            MCP_SAMPLING_MAX_OUTPUT_TOKENS,
            max(1, int(max_tokens)) if max_tokens is not None else MCP_SAMPLING_MAX_OUTPUT_TOKENS,
        ),
    }
    return {"requested": requested, "effective": effective}


def _sampling_policy_payload(budget: dict[str, Any], execution_mode: str) -> dict[str, Any]:
    return {
        "schema": "mcp_sampling_policy.v1",
        "enabled": bool(MCP_SAMPLING_ENABLED),
        "allowed_use_cases": sorted(_sampling_allowed_use_cases()),
        "hard_denied_use_cases": list(_SAMPLING_HARD_DENIED_USE_CASES),
        "budgets": budget,
        "model_preferences": {
            "hints": _sampling_model_hints(),
            "cost_priority": 0.2,
            "speed_priority": 0.4,
            "intelligence_priority": 0.4,
            "max_output_tokens": budget["effective"]["max_output_tokens"],
        },
        "human_review_required": True,
        "client_mediated": True,
        "no_silent_model_calls": True,
        "output_authority": "advisory_only",
        "execution_mode": execution_mode,
        "online_offline_behavior": {
            "online": "Client-mediated sampling may use the client's configured model only after client/user review.",
            "offline": "Client-mediated sampling is still explicit; clients must keep any model call onboard/local if offline privacy is required.",
        },
        "redaction": "repository-relative context only; secret-looking values, private keys, and host absolute paths are redacted before prompt construction",
    }


def _sampling_base_result(
    *,
    status: str,
    reason: str,
    purpose: str,
    execution_mode: str,
    execution_mode_source: str,
    policy: dict[str, Any],
    capability: dict[str, Any] | None = None,
    context: dict[str, Any] | None = None,
    request: dict[str, Any] | None = None,
    sampling: dict[str, Any] | None = None,
    audit: dict[str, Any] | None = None,
    guidance: list[str] | None = None,
) -> dict[str, Any]:
    return {
        "schema": "model_assisted_summary.v1",
        "ok": status in {"approved", "prepared"},
        "status": status,
        "reason": reason,
        "read_only": True,
        "advisory_only": True,
        "purpose": purpose,
        "execution_mode": execution_mode,
        "execution_mode_source": execution_mode_source,
        "policy": policy,
        "capability": capability
        or {
            "client_session_active": False,
            "sampling_declared": False,
            "create_message_api": False,
            "status": "unavailable",
            "reason": "not_probed",
        },
        "context": context
        or {
            "repo_boundary_enforced": True,
            "sources": [],
            "omitted": [],
            "redactions_applied": [],
            "estimated_tokens": 0,
            "included_bytes": 0,
            "prompt_contains_raw_repository_content": False,
        },
        "request": request
        or {
            "would_call_client": False,
            "dry_run": False,
            "human_review_expected": True,
            "include_context": "none",
            "metadata": {},
        },
        "sampling": sampling
        or {
            "model": "",
            "stop_reason": "",
            "summary": "",
            "output_digest": {},
        },
        "audit": audit
        or {
            "records_raw_prompt": False,
            "records_raw_response": False,
            "records_repository_content": False,
            "approval_status": "not_observed",
            "prompt_digest": {},
            "output_digest": {},
        },
        "guidance": guidance
        or [
            "Generated text is advisory only; cite raw tool results/artifacts before release, security, or destructive decisions.",
            "No repository content is sampled unless MCP_SAMPLING_ENABLED is true and the client declares sampling capability.",
        ],
    }


def _sampling_context_from_paths(
    paths: list[str] | None,
    *,
    budget: dict[str, Any],
) -> tuple[str, dict[str, Any]]:
    effective = budget["effective"]
    max_paths = int(effective["max_paths"])
    max_bytes = int(effective["max_bytes"])
    max_context_tokens = int(effective["max_context_tokens"])
    raw_paths = [str(item).strip() for item in (paths or []) if str(item).strip()]
    if not raw_paths:
        raw_paths = _sampling_default_paths(max_paths)
    if len(raw_paths) > max_paths:
        return "", {
            "repo_boundary_enforced": True,
            "sources": [],
            "omitted": [
                {
                    "reason": "path_budget_exceeded",
                    "requested_paths": len(raw_paths),
                    "max_paths": max_paths,
                }
            ],
            "redactions_applied": [],
            "estimated_tokens": 0,
            "included_bytes": 0,
            "prompt_contains_raw_repository_content": False,
            "budget_violation": "path_budget_exceeded",
        }

    sources: list[dict[str, Any]] = []
    omitted: list[dict[str, Any]] = []
    redactions: list[str] = []
    chunks: list[str] = []
    included_bytes = 0
    remaining_chars = max_context_tokens * 4

    for index, raw in enumerate(raw_paths):
        rel_for_policy = raw.replace("\\", "/").lstrip("/")
        if _SAMPLING_SECRET_PATH_RE.search(rel_for_policy):
            omitted.append({"path": rel_for_policy, "reason": "secret_bearing_path_denied"})
            continue
        try:
            path = _resolve_repo_path(raw)
        except ValueError:
            omitted.append({"path": rel_for_policy, "reason": "path_escapes_repository"})
            continue
        if not path.is_file():
            omitted.append({"path": rel_for_policy, "reason": "not_a_regular_file"})
            continue
        rel = str(path.relative_to(REPO_PATH)).replace("\\", "/")
        if _SAMPLING_SECRET_PATH_RE.search(rel):
            omitted.append({"path": rel, "reason": "secret_bearing_path_denied"})
            continue
        if included_bytes >= max_bytes or remaining_chars <= 0:
            omitted.append({"path": rel, "reason": "byte_or_token_budget_exhausted"})
            continue
        try:
            size = path.stat().st_size
            read_limit = min(size, max_bytes - included_bytes)
            with path.open("rb") as handle:
                data = handle.read(read_limit)
        except OSError:
            omitted.append({"path": rel, "reason": "read_failed"})
            continue
        text = data.decode("utf-8", errors="replace")
        redacted, redaction_codes = _sampling_redact_text(text)
        for code in redaction_codes:
            if code not in redactions:
                redactions.append(code)
        token_truncated = False
        if len(redacted) > remaining_chars:
            redacted = redacted[: max(0, remaining_chars)]
            token_truncated = True
            if "token_budget_truncated" not in redactions:
                redactions.append("token_budget_truncated")
        chunk_digest = _sampling_digest_text(redacted)
        chunks.append(
            f"FILE: {rel}\n"
            f"REDACTED_SHA256: {chunk_digest['value']}\n"
            "---\n"
            f"{redacted}\n"
            "---"
        )
        included_bytes += len(data)
        remaining_chars -= len(redacted)
        truncated = bool(size > read_limit or token_truncated)
        sources.append(
            {
                "path": rel,
                "size_bytes": int(size),
                "included_bytes": len(data),
                "estimated_tokens": _sampling_estimated_tokens(redacted),
                "truncated": truncated,
                "redacted_digest": chunk_digest,
            }
        )
        if size > read_limit:
            omitted.append({"path": rel, "reason": "byte_budget_truncated"})
        if token_truncated:
            omitted.append({"path": rel, "reason": "token_budget_truncated"})
        if remaining_chars <= 0:
            remaining_paths = [p for p in raw_paths[index + 1 :]]
            for later in remaining_paths:
                omitted.append(
                    {
                        "path": later.replace("\\", "/").lstrip("/"),
                        "reason": "token_budget_exhausted",
                    }
                )
            break

    context_text = "\n\n".join(chunks)
    return context_text, {
        "repo_boundary_enforced": True,
        "sources": sources,
        "omitted": omitted,
        "redactions_applied": redactions,
        "estimated_tokens": _sampling_estimated_tokens(context_text),
        "included_bytes": included_bytes,
        "max_bytes": max_bytes,
        "max_context_tokens": max_context_tokens,
        "prompt_contains_raw_repository_content": False,
        "prompt_contains_redacted_repository_content": bool(sources),
        "budget_violation": "" if sources else "no_context_available",
    }


def _sampling_prompt(
    *,
    purpose: str,
    question: str,
    context_text: str,
    execution_mode: str,
) -> tuple[str, list[str]]:
    safe_question, question_redactions = _sampling_redact_text(question.strip())
    if not safe_question:
        safe_question = "Summarize the bounded repository context for an engineering handoff."
    purpose_instruction = {
        "summary": "Return a concise repository-context summary with uncertainty notes.",
        "classification": "Return only a concise classification and supporting non-sensitive rationale.",
        "workflow_selection": "Classify the likely workflow family; do not approve release, security, or mutation decisions.",
    }.get(purpose, "Return a concise bounded summary.")
    prompt = (
        "You are assisting codebase-tooling-mcp through MCP Sampling.\n"
        "The client/user remains in control of model access and approval.\n"
        "Use only the redacted repository-relative context below.\n"
        "Do not request credentials, infer secrets, or rely on host absolute paths.\n"
        "Do not recommend destructive changes, release approval, or security conclusions as final.\n"
        "Generated text is advisory only; raw tool results/artifacts must support high-risk decisions.\n\n"
        f"Purpose: {purpose}\n"
        f"Execution mode: {execution_mode}\n"
        f"Allowed output: {purpose_instruction}\n"
        f"Question: {safe_question}\n\n"
        "Repository context (redacted, compressed, bounded):\n"
        f"{context_text}"
    )
    return prompt, question_redactions


def _sampling_make_messages(prompt: str) -> list[Any]:
    try:
        from mcp.types import SamplingMessage, TextContent

        return [
            SamplingMessage(
                role="user",
                content=TextContent(type="text", text=prompt),
            )
        ]
    except Exception:
        return [{"role": "user", "content": {"type": "text", "text": prompt}}]


def _sampling_model_preferences() -> Any:
    hints = _sampling_model_hints()
    try:
        from mcp.types import ModelHint, ModelPreferences

        return ModelPreferences(
            hints=[ModelHint(name=item) for item in hints] or None,
            costPriority=0.2,
            speedPriority=0.4,
            intelligencePriority=0.4,
        )
    except Exception:
        return {
            "hints": [{"name": item} for item in hints],
            "costPriority": 0.2,
            "speedPriority": 0.4,
            "intelligencePriority": 0.4,
        }


def _sampling_value(value: Any, key: str, default: Any = None) -> Any:
    if isinstance(value, dict):
        return value.get(key, default)
    return getattr(value, key, default)


def _sampling_extract_response_text(response: Any) -> str:
    content = _sampling_value(response, "content", None)
    if isinstance(content, list):
        return "\n".join(_sampling_extract_response_text({"content": item}) for item in content)
    if isinstance(content, dict):
        if content.get("type") == "text" or "text" in content:
            return str(content.get("text", ""))
        return _trim_text(json.dumps(_redact_audit_value(content), sort_keys=True), max_chars=2000)
    text = getattr(content, "text", None)
    if text is not None:
        return str(text)
    if isinstance(response, str):
        return response
    return ""


def _sampling_response_meta(response: Any) -> dict[str, Any]:
    meta = _sampling_value(response, "meta", None)
    if meta is None:
        meta = _sampling_value(response, "_meta", None)
    return meta if isinstance(meta, dict) else {}


def _sampling_denial_error(exc: Exception) -> bool:
    text = f"{exc.__class__.__name__} {exc}".lower()
    return any(term in text for term in ("denied", "deny", "declined", "cancelled", "canceled"))


def _sampling_audit_payload(result: dict[str, Any]) -> dict[str, Any]:
    request = result.get("request", {}) if isinstance(result.get("request"), dict) else {}
    context = result.get("context", {}) if isinstance(result.get("context"), dict) else {}
    audit = result.get("audit", {}) if isinstance(result.get("audit"), dict) else {}
    return {
        "purpose": result.get("purpose", ""),
        "status": result.get("status", ""),
        "reason": result.get("reason", ""),
        "execution_mode": result.get("execution_mode", ""),
        "approval_status": audit.get("approval_status", "not_observed"),
        "prompt_digest": audit.get("prompt_digest", {}),
        "output_digest": audit.get("output_digest", {}),
        "context_sources": [
            {
                "path": row.get("path", ""),
                "redacted_digest": row.get("redacted_digest", {}),
                "included_bytes": row.get("included_bytes", 0),
                "truncated": row.get("truncated", False),
            }
            for row in context.get("sources", [])[:10]
            if isinstance(row, dict)
        ],
        "redactions_applied": list(context.get("redactions_applied", []))[:10],
        "metadata": request.get("metadata", {}),
        "records_raw_prompt": False,
        "records_raw_response": False,
        "records_repository_content": False,
    }


async def _client_sampling_capability(session: Any | None) -> dict[str, Any]:
    if session is None:
        return {
            "client_session_active": False,
            "sampling_declared": False,
            "create_message_api": False,
            "status": "unavailable",
            "reason": "no_active_mcp_request_session",
        }
    has_create_message = hasattr(session, "create_message")
    checker = getattr(session, "check_client_capability", None)
    sampling_declared = False
    reason = "client_sampling_capability_not_advertised"
    if checker is not None:
        try:
            from mcp.types import ClientCapabilities, SamplingCapability

            sampling_declared = bool(
                await _maybe_await(checker(ClientCapabilities(sampling=SamplingCapability())))
            )
        except Exception:
            sampling_declared = False
            reason = "client_sampling_capability_probe_failed"
    else:
        capabilities = getattr(session, "client_capabilities", None)
        if isinstance(capabilities, dict):
            sampling_declared = bool(capabilities.get("sampling"))
        else:
            sampling_declared = bool(
                getattr(capabilities, "sampling", None)
                if capabilities is not None
                else False
            )
        if not sampling_declared:
            reason = "session_has_no_sampling_capability_probe"
    if sampling_declared and not has_create_message:
        reason = "session_has_no_create_message_api"
    elif sampling_declared:
        reason = "sampling_capability_declared"
    return {
        "client_session_active": True,
        "sampling_declared": bool(sampling_declared),
        "create_message_api": bool(has_create_message),
        "status": "available" if sampling_declared and has_create_message else "unsupported",
        "reason": reason,
    }


@mcp.tool()
async def roots_diagnostics(timeout_seconds: float = 1.0) -> dict[str, Any]:
    """Read-only MCP roots diagnostic comparing client roots with REPO_PATH."""
    if timeout_seconds <= 0:
        timeout_seconds = 1.0
    timeout_seconds = min(float(timeout_seconds), 5.0)
    session = _active_mcp_session()
    if session is None:
        payload = _roots_base_payload("unavailable", "unavailable")
        payload["fetch"]["reason"] = "no_active_mcp_request_session"
        return payload

    if not hasattr(session, "list_roots"):
        payload = _roots_base_payload("unsupported", "unsupported")
        payload["fetch"]["reason"] = "session_has_no_list_roots_api"
        return payload

    if not await _client_roots_supported(session):
        payload = _roots_base_payload("unsupported", "unsupported")
        payload["fetch"]["reason"] = "client_roots_capability_not_advertised"
        return payload

    try:
        result = await asyncio.wait_for(session.list_roots(), timeout=timeout_seconds)
    except asyncio.TimeoutError:
        payload = _roots_base_payload("error", "timeout")
        payload["fetch"]["reason"] = "roots_list_timeout"
        return payload
    except Exception as exc:
        payload = _roots_base_payload("error", "error")
        payload["fetch"].update({"reason": "roots_list_failed", "error": exc.__class__.__name__})
        return payload

    roots = getattr(result, "roots", result)
    if roots is None:
        roots = []
    if not isinstance(roots, list):
        try:
            roots = list(roots)
        except TypeError:
            payload = _roots_base_payload("error", "error")
            payload["fetch"]["reason"] = "roots_result_invalid"
            payload["roots"]["invalid_count"] = 1
            return payload
    return _summarize_roots_result(roots)


@mcp.tool()
async def model_assisted_summary(
    purpose: Annotated[
        str,
        Field(
            description="Allowed MCP sampling purpose: summary, classification, or workflow_selection. Mutations, release approval, and security conclusions are denied."
        ),
    ] = "summary",
    paths: Annotated[
        list[str] | None,
        Field(
            description="Repository-relative files to summarize/classify. Defaults to small repository overview docs. Secret-bearing paths and paths outside REPO_PATH are denied/omitted."
        ),
    ] = None,
    question: Annotated[
        str,
        Field(
            description="Optional bounded question. Secret-looking values and host absolute paths are redacted before any client-mediated sampling request."
        ),
    ] = "",
    execution_mode: Annotated[
        str,
        Field(
            description="Agent execution profile (`auto`, `online`, or `offline`). Offline mode is explicit metadata; clients must keep sampling local/onboard if privacy requires it."
        ),
    ] = "auto",
    max_paths: Annotated[int | None, Field(description="Optional per-call path cap, clamped by MCP_SAMPLING_MAX_PATHS.")] = None,
    max_bytes: Annotated[int | None, Field(description="Optional per-call byte cap, clamped by MCP_SAMPLING_MAX_BYTES.")] = None,
    max_context_tokens: Annotated[
        int | None,
        Field(description="Optional estimated context-token cap, clamped by MCP_SAMPLING_MAX_CONTEXT_TOKENS."),
    ] = None,
    max_tokens: Annotated[
        int | None,
        Field(description="Optional generated-token cap, clamped by MCP_SAMPLING_MAX_OUTPUT_TOKENS."),
    ] = None,
    dry_run: Annotated[
        bool,
        Field(description="Prepare policy/context/digests without sending a sampling/createMessage request."),
    ] = False,
    timeout_seconds: Annotated[
        float,
        Field(description="Client-mediated sampling timeout in seconds; capped at 30 seconds."),
    ] = 20.0,
) -> dict[str, Any]:
    """Disabled-by-default MCP sampling safety adapter for bounded advisory repo summaries/classifications."""
    purpose_norm = str(purpose or "summary").strip().lower().replace("-", "_")
    try:
        resolved_mode, mode_source = _resolve_agent_execution_mode(
            execution_mode,
            f"sampling {purpose_norm} {question}",
        )
    except ValueError:
        resolved_mode, mode_source = "online", "fallback_after_invalid_request"
    budget = _sampling_effective_budget(
        max_paths=max_paths,
        max_bytes=max_bytes,
        max_context_tokens=max_context_tokens,
        max_tokens=max_tokens,
    )
    policy = _sampling_policy_payload(budget, resolved_mode)
    audit_args = {
        "purpose": purpose_norm,
        "execution_mode": resolved_mode,
        "execution_mode_source": mode_source,
        "dry_run": dry_run,
        "path_count": len(paths or []),
        "question_length": len(question or ""),
        "budgets": budget["effective"],
    }
    categories = _tool_categories("model_assisted_summary", audit_args)
    with _otel_span(
        "mcp.tool.model_assisted_summary",
        _otel_tool_attributes("model_assisted_summary", audit_args, categories),
    ) as span:
        categories = _require_tool_security_gate("model_assisted_summary", audit_args)
        span.set_attribute("mcp.tool.categories", sorted(str(item) for item in categories))
        sensitive = bool(SENSITIVE_TOOL_CATEGORIES.intersection(categories))
        result: dict[str, Any]
        try:
            session = _active_mcp_session()
            capability = await _client_sampling_capability(session)
            if purpose_norm in _SAMPLING_HARD_DENIED_USE_CASES:
                result = _sampling_base_result(
                    status="denied",
                    reason="hard_denied_use_case",
                    purpose=purpose_norm,
                    execution_mode=resolved_mode,
                    execution_mode_source=mode_source,
                    policy=policy,
                    capability=capability,
                )
            elif purpose_norm not in _sampling_allowed_use_cases():
                result = _sampling_base_result(
                    status="denied",
                    reason="purpose_not_allowed",
                    purpose=purpose_norm,
                    execution_mode=resolved_mode,
                    execution_mode_source=mode_source,
                    policy=policy,
                    capability=capability,
                )
            elif not MCP_SAMPLING_ENABLED:
                result = _sampling_base_result(
                    status="disabled",
                    reason="MCP_SAMPLING_ENABLED is false",
                    purpose=purpose_norm,
                    execution_mode=resolved_mode,
                    execution_mode_source=mode_source,
                    policy=policy,
                    capability=capability,
                )
            elif capability.get("status") != "available":
                result = _sampling_base_result(
                    status="unsupported",
                    reason=str(capability.get("reason", "sampling_unavailable")),
                    purpose=purpose_norm,
                    execution_mode=resolved_mode,
                    execution_mode_source=mode_source,
                    policy=policy,
                    capability=capability,
                )
            else:
                context_text, context_meta = _sampling_context_from_paths(paths, budget=budget)
                if context_meta.get("budget_violation") == "path_budget_exceeded":
                    result = _sampling_base_result(
                        status="denied",
                        reason="path_budget_exceeded",
                        purpose=purpose_norm,
                        execution_mode=resolved_mode,
                        execution_mode_source=mode_source,
                        policy=policy,
                        capability=capability,
                        context=context_meta,
                    )
                elif not context_meta.get("sources"):
                    result = _sampling_base_result(
                        status="denied",
                        reason="no_allowed_repository_context",
                        purpose=purpose_norm,
                        execution_mode=resolved_mode,
                        execution_mode_source=mode_source,
                        policy=policy,
                        capability=capability,
                        context=context_meta,
                    )
                else:
                    prompt, question_redactions = _sampling_prompt(
                        purpose=purpose_norm,
                        question=question,
                        context_text=context_text,
                        execution_mode=resolved_mode,
                    )
                    for code in question_redactions:
                        if code not in context_meta["redactions_applied"]:
                            context_meta["redactions_applied"].append(code)
                    prompt_digest = _sampling_digest_text(prompt)
                    metadata = {
                        "schema": "mcp_sampling_request_metadata.v1",
                        "server": "codebase-tooling-mcp",
                        "purpose": purpose_norm,
                        "execution_mode": resolved_mode,
                        "human_review_expected": True,
                        "advisory_only": True,
                        "repository_boundary_enforced": True,
                        "redaction_applied": True,
                        "prompt_digest": prompt_digest,
                        "context_source_count": len(context_meta.get("sources", [])),
                        "forbidden_decisions": [
                            "mutation",
                            "release_approval",
                            "security_conclusion",
                            "credential_handling",
                        ],
                    }
                    request_meta = {
                        "would_call_client": not dry_run,
                        "dry_run": bool(dry_run),
                        "human_review_expected": True,
                        "include_context": "none",
                        "max_tokens": budget["effective"]["max_output_tokens"],
                        "metadata": metadata,
                        "model_preferences": policy["model_preferences"],
                        "prompt_digest": prompt_digest,
                    }
                    audit_meta = {
                        "records_raw_prompt": False,
                        "records_raw_response": False,
                        "records_repository_content": False,
                        "approval_status": "not_observed",
                        "prompt_digest": prompt_digest,
                        "output_digest": {},
                    }
                    if dry_run:
                        result = _sampling_base_result(
                            status="prepared",
                            reason="dry_run_prepared_without_client_call",
                            purpose=purpose_norm,
                            execution_mode=resolved_mode,
                            execution_mode_source=mode_source,
                            policy=policy,
                            capability=capability,
                            context=context_meta,
                            request=request_meta,
                            audit=audit_meta,
                        )
                    else:
                        try:
                            response = await asyncio.wait_for(
                                _maybe_await(
                                    session.create_message(
                                        messages=_sampling_make_messages(prompt),
                                        max_tokens=budget["effective"]["max_output_tokens"],
                                        system_prompt=(
                                            "Return bounded summary/classification only. Output is advisory; do not make release, security, or mutation decisions."
                                        ),
                                        include_context="none",
                                        temperature=0.1,
                                        metadata=metadata,
                                        model_preferences=_sampling_model_preferences(),
                                    )
                                ),
                                timeout=max(1.0, min(float(timeout_seconds), 30.0)),
                            )
                        except Exception as exc:
                            status = "denied" if _sampling_denial_error(exc) else "error"
                            reason = "client_denied_sampling" if status == "denied" else exc.__class__.__name__
                            audit_meta["approval_status"] = "denied" if status == "denied" else "not_observed"
                            request_meta["would_call_client"] = True
                            result = _sampling_base_result(
                                status=status,
                                reason=reason,
                                purpose=purpose_norm,
                                execution_mode=resolved_mode,
                                execution_mode_source=mode_source,
                                policy=policy,
                                capability=capability,
                                context=context_meta,
                                request=request_meta,
                                audit=audit_meta,
                            )
                        else:
                            raw_output = _sampling_extract_response_text(response)
                            safe_output, output_redactions = _sampling_redact_text(raw_output)
                            for code in output_redactions:
                                if code not in context_meta["redactions_applied"]:
                                    context_meta["redactions_applied"].append(code)
                            safe_output = _trim_text(safe_output, max_chars=MAX_OUTPUT_CHARS)
                            output_digest = _sampling_digest_text(safe_output)
                            response_meta = _sampling_response_meta(response)
                            approval_status = str(
                                response_meta.get("approval_status")
                                or response_meta.get("human_review")
                                or response_meta.get("review_status")
                                or "client_mediated"
                            )
                            audit_meta["approval_status"] = approval_status
                            audit_meta["output_digest"] = output_digest
                            sampling_payload = {
                                "model": str(_sampling_value(response, "model", "")),
                                "stop_reason": str(_sampling_value(response, "stopReason", "") or _sampling_value(response, "stop_reason", "")),
                                "summary": safe_output,
                                "output_digest": output_digest,
                                "response_redacted": bool(output_redactions),
                            }
                            result = _sampling_base_result(
                                status="approved",
                                reason="client_returned_sampling_response",
                                purpose=purpose_norm,
                                execution_mode=resolved_mode,
                                execution_mode_source=mode_source,
                                policy=policy,
                                capability=capability,
                                context=context_meta,
                                request=request_meta,
                                sampling=sampling_payload,
                                audit=audit_meta,
                            )
        except Exception as exc:
            if sensitive:
                _append_audit_event(
                    "model_assisted_summary",
                    categories,
                    False,
                    audit_args,
                    exc.__class__.__name__,
                    required_scope=_required_scope_for_categories(categories),
                    granted_scopes=(
                        _http_request_granted_scopes_for_tools() if _inside_http_request() else None
                    ),
                )
            raise
        _otel_set_result_attributes(span, result)
        span.set_attribute("mcp.sampling.status", result.get("status", ""))
        span.set_attribute("mcp.sampling.purpose", purpose_norm)
        span.set_attribute("mcp.sampling.approval_status", result.get("audit", {}).get("approval_status", "not_observed"))
        prompt_digest_value = result.get("audit", {}).get("prompt_digest", {}).get("value", "")
        if prompt_digest_value:
            span.set_attribute("mcp.sampling.prompt_digest", prompt_digest_value)
        output_digest_value = result.get("audit", {}).get("output_digest", {}).get("value", "")
        if output_digest_value:
            span.set_attribute("mcp.sampling.output_digest", output_digest_value)
        if sensitive:
            _append_audit_event(
                "model_assisted_summary",
                categories,
                _tool_result_success(result),
                _sampling_audit_payload(result),
                _tool_result_failure_reason(result),
                required_scope=_required_scope_for_categories(categories),
                granted_scopes=(
                    _http_request_granted_scopes_for_tools() if _inside_http_request() else None
                ),
            )
        return result


@mcp.tool()
def runtime_state() -> dict[str, Any]:
    """Return process/port/dependency runtime state for server and optional Ollama."""
    return _runtime_state_payload(include_ollama_probe=True)


def docker_cli_status() -> dict[str, Any]:
    """Report docker CLI/socket awareness and daemon reachability signals."""
    return {
        "schema": "docker_cli_status.v1",
        **_docker_cli_status(),
    }


def docker_cli_run(
    command: list[str],
    cwd: str = ".",
    control_profile: str = "build",
    timeout_seconds: int = 1800,
    max_output_chars: int | None = None,
) -> dict[str, Any]:
    """Run a validated Docker CLI command directly."""
    _require_mutations()
    if timeout_seconds < 1:
        raise ValueError("timeout_seconds must be >= 1")
    out_cap = _token_budget_apply_max(max_output_chars)
    _validate_build_task_command(command, control_profile=control_profile)

    workdir = _resolve_repo_path(cwd)

    try:
        proc = subprocess.run(
            command,
            cwd=str(workdir),
            check=False,
            capture_output=True,
            text=True,
            timeout=timeout_seconds,
        )
    except subprocess.TimeoutExpired as exc:
        timeout_stdout = (exc.stdout or "") if isinstance(exc.stdout, str) else ""
        timeout_stderr = (exc.stderr or "") if isinstance(exc.stderr, str) else ""
        build_log_tail = _summarize_build_log(timeout_stdout, timeout_stderr)
        proposals = _build_log_proposals(timeout_stdout, timeout_stderr)
        return {
            "schema": "docker_cli_run.v1",
            "ok": False,
            "command": command,
            "cwd": rel_cwd,
            "control_profile": control_profile,
            "exit_code": None,
            "timeout": True,
            "stdout": _trim_text(timeout_stdout, max_chars=out_cap),
            "stderr": _trim_text(timeout_stderr, max_chars=out_cap),
            "build_log_tail": _trim_text(build_log_tail, max_chars=out_cap),
            "proposals": proposals,
        }

    build_log_tail = _summarize_build_log(proc.stdout, proc.stderr)
    proposals: list[dict[str, str]] = []
    if proc.returncode != 0:
        proposals = _build_log_proposals(proc.stdout, proc.stderr)
    return {
        "schema": "docker_cli_run.v1",
        "ok": proc.returncode == 0,
        "command": command,
        "cwd": str(workdir.relative_to(REPO_PATH)),
        "control_profile": control_profile,
        "exit_code": proc.returncode,
        "timeout": False,
        "stdout": _trim_text(proc.stdout, max_chars=out_cap),
        "stderr": _trim_text(proc.stderr, max_chars=out_cap),
        "build_log_tail": _trim_text(build_log_tail, max_chars=out_cap),
        "proposals": proposals,
    }


class DockerRouterService:
    """Application service for Docker CLI routing."""

    def route(
        self,
        mode: str = "status",
        command: list[str] | None = None,
        cwd: str = ".",
        control_profile: str = "build",
        timeout_seconds: int = 1800,
        max_output_chars: int | None = None,
    ) -> dict[str, Any]:
        if mode not in {"status", "run"}:
            raise ValueError("mode must be one of: status, run")
        if mode == "status":
            return {
                "schema": "docker_router.v1",
                "mode": mode,
                "result": docker_cli_status(),
            }
        if not command:
            raise ValueError("command is required for run mode")
        return {
            "schema": "docker_router.v1",
            "mode": mode,
            "result": docker_cli_run(
                command=command,
                cwd=cwd,
                control_profile=control_profile,
                timeout_seconds=timeout_seconds,
                max_output_chars=max_output_chars,
            ),
        }


class VSCodeRouterService:
    """Application service for VS Code tasks routing."""

    def route(
        self,
        mode: str = "list",
        label: str = "",
        tasks_path: str = ".vscode/tasks.json",
        label_prefix: str = "",
        control_profile: str = "build",
        timeout_seconds: int = 1800,
        max_output_chars: int | None = None,
    ) -> dict[str, Any]:
        if mode not in {"list", "run"}:
            raise ValueError("mode must be one of: list, run")
        if mode == "list":
            return {
                "schema": "vscode_router.v1",
                "mode": mode,
                "result": vscode_tasks_list(
                    tasks_path=tasks_path,
                    label_prefix=label_prefix,
                    control_profile=control_profile,
                ),
            }
        if not label.strip():
            raise ValueError("label is required for run mode")
        return {
            "schema": "vscode_router.v1",
            "mode": mode,
            "result": vscode_task_run(
                label=label,
                tasks_path=tasks_path,
                control_profile=control_profile,
                timeout_seconds=timeout_seconds,
                max_output_chars=max_output_chars,
            ),
        }


_DOCKER_ROUTER_SERVICE = DockerRouterService()
_VSCODE_ROUTER_SERVICE = VSCodeRouterService()


@mcp.tool()
def docker_router(
    mode: str = "status",
    command: list[str] | None = None,
    cwd: str = ".",
    control_profile: str = "build",
    timeout_seconds: int = 1800,
    max_output_chars: int | None = None,
) -> dict[str, Any]:
    """Docker CLI gateway. mode=status|run; run validates the command against the selected control profile."""
    arguments = {
        "mode": mode,
        "command": command,
        "cwd": cwd,
        "control_profile": control_profile,
        "timeout_seconds": timeout_seconds,
        "max_output_chars": max_output_chars,
    }
    return _run_with_tool_security_audit(
        "docker_router",
        arguments,
        lambda: _DOCKER_ROUTER_SERVICE.route(
            mode=mode,
            command=command,
            cwd=cwd,
            control_profile=control_profile,
            timeout_seconds=timeout_seconds,
            max_output_chars=max_output_chars,
        ),
    )


@mcp.tool()
def vscode_router(
    mode: str = "list",
    label: str = "",
    tasks_path: str = ".vscode/tasks.json",
    label_prefix: str = "",
    control_profile: str = "build",
    timeout_seconds: int = 1800,
    max_output_chars: int | None = None,
) -> dict[str, Any]:
    """VS Code task gateway. mode=list|run; list filters tasks.json and run executes one exact label."""
    arguments = {
        "mode": mode,
        "label": label,
        "tasks_path": tasks_path,
        "label_prefix": label_prefix,
        "control_profile": control_profile,
        "timeout_seconds": timeout_seconds,
        "max_output_chars": max_output_chars,
    }
    return _run_with_tool_security_audit(
        "vscode_router",
        arguments,
        lambda: _VSCODE_ROUTER_SERVICE.route(
            mode=mode,
            label=label,
            tasks_path=tasks_path,
            label_prefix=label_prefix,
            control_profile=control_profile,
            timeout_seconds=timeout_seconds,
            max_output_chars=max_output_chars,
        ),
    )


def vscode_tasks_list(
    tasks_path: str = ".vscode/tasks.json",
    label_prefix: str = "",
    control_profile: str = "build",
) -> dict[str, Any]:
    """List VS Code tasks and whether each is runnable under the selected control profile."""
    tasks_file, tasks = _load_vscode_tasks(tasks_path)
    rows: list[dict[str, Any]] = []
    for task in tasks:
        label = str(task.get("label", "")).strip()
        if label_prefix and not label.startswith(label_prefix):
            continue
        try:
            cmd = _task_command_from_vscode_task(task)
            _validate_build_task_command(cmd, control_profile=control_profile)
            rows.append(
                {
                    "label": label,
                    "ok": True,
                    "command": cmd,
                }
            )
        except Exception as exc:
            rows.append(
                {
                    "label": label,
                    "ok": False,
                    "error": str(exc),
                }
            )
    return {
        "schema": "vscode_tasks_list.v1",
        "tasks_path": str(tasks_file.relative_to(REPO_PATH)),
        "label_prefix": label_prefix,
        "control_profile": control_profile,
        "count": len(rows),
        "tasks": rows,
    }


def vscode_task_run(
    label: str,
    tasks_path: str = ".vscode/tasks.json",
    control_profile: str = "build",
    timeout_seconds: int = 1800,
    max_output_chars: int | None = None,
) -> dict[str, Any]:
    """Run an approved Docker task by label from VS Code tasks.json."""
    _require_mutations()
    if timeout_seconds < 1:
        raise ValueError("timeout_seconds must be >= 1")
    out_cap = _token_budget_apply_max(max_output_chars)
    tasks_file, tasks = _load_vscode_tasks(tasks_path)

    selected: dict[str, Any] | None = None
    for task in tasks:
        if str(task.get("label", "")).strip() == label:
            selected = task
            break
    if selected is None:
        raise ValueError(f"task not found: {label}")

    command = _task_command_from_vscode_task(selected)
    _validate_build_task_command(command, control_profile=control_profile)

    options = selected.get("options", {})
    task_cwd = "."
    if isinstance(options, dict):
        task_cwd_value = options.get("cwd")
        if isinstance(task_cwd_value, str) and task_cwd_value.strip():
            task_cwd = task_cwd_value
    if task_cwd.startswith("${workspaceFolder}"):
        suffix = task_cwd[len("${workspaceFolder}") :].lstrip("/\\")
        task_cwd = suffix or "."
    workdir = _resolve_repo_path(task_cwd)
    rel_cwd = str(workdir.relative_to(REPO_PATH))

    workflow_task_id = _WORKFLOW_TASK_CURRENT_ID.get("")
    try:
        proc = _run_subprocess_with_workflow_cancellation(
            command,
            cwd=str(workdir),
            timeout_seconds=timeout_seconds,
            task_id=workflow_task_id,
        )
    except _WorkflowTaskCancelled as exc:
        cancel_stdout = exc.stdout or ""
        cancel_stderr = exc.stderr or ""
        build_log_tail = _summarize_build_log(cancel_stdout, cancel_stderr)
        proposals = _build_log_proposals(cancel_stdout, cancel_stderr)
        return {
            "schema": "vscode_task_run.v1",
            "ok": False,
            "label": label,
            "tasks_path": str(tasks_file.relative_to(REPO_PATH)),
            "control_profile": control_profile,
            "command": command,
            "cwd": rel_cwd,
            "exit_code": None,
            "timeout": False,
            "cancelled": True,
            "stdout": _trim_text(cancel_stdout, max_chars=out_cap),
            "stderr": _trim_text(cancel_stderr, max_chars=out_cap),
            "build_log_tail": _trim_text(build_log_tail, max_chars=out_cap),
            "proposals": proposals,
        }
    except subprocess.TimeoutExpired as exc:
        timeout_stdout = (exc.stdout or "") if isinstance(exc.stdout, str) else ""
        timeout_stderr = (exc.stderr or "") if isinstance(exc.stderr, str) else ""
        build_log_tail = _summarize_build_log(timeout_stdout, timeout_stderr)
        proposals = _build_log_proposals(timeout_stdout, timeout_stderr)
        return {
            "schema": "vscode_task_run.v1",
            "ok": False,
            "label": label,
            "tasks_path": str(tasks_file.relative_to(REPO_PATH)),
            "control_profile": control_profile,
            "command": command,
            "cwd": rel_cwd,
            "exit_code": None,
            "timeout": True,
            "stdout": _trim_text(timeout_stdout, max_chars=out_cap),
            "stderr": _trim_text(timeout_stderr, max_chars=out_cap),
            "build_log_tail": _trim_text(build_log_tail, max_chars=out_cap),
            "proposals": proposals,
        }

    build_log_tail = _summarize_build_log(proc.stdout, proc.stderr)
    proposals: list[dict[str, str]] = []
    if proc.returncode != 0:
        proposals = _build_log_proposals(proc.stdout, proc.stderr)

    return {
        "schema": "vscode_task_run.v1",
        "ok": proc.returncode == 0,
        "label": label,
        "tasks_path": str(tasks_file.relative_to(REPO_PATH)),
        "control_profile": control_profile,
        "command": command,
        "cwd": str(workdir.relative_to(REPO_PATH)),
        "exit_code": proc.returncode,
        "timeout": False,
        "stdout": _trim_text(proc.stdout, max_chars=out_cap),
        "stderr": _trim_text(proc.stderr, max_chars=out_cap),
        "build_log_tail": _trim_text(build_log_tail, max_chars=out_cap),
        "proposals": proposals,
    }


@mcp.tool()
def git_init(initial_branch: str = "main") -> dict[str, str]:
    """Initialize a Git repository in the mounted directory."""
    _require_mutations()
    _ensure_repo_path_exists()
    if _is_git_repo():
        raise ValueError(f"{REPO_PATH} is already a Git working tree")

    _git("init", "-b", initial_branch)
    return {
        "repo_path": str(REPO_PATH),
        "message": f"initialized repository with initial branch '{initial_branch}'",
    }


@mcp.tool()
def list_files(
    path: str = ".",
    recursive: bool = True,
    include_hidden: bool = False,
    max_entries: int = 1000,
) -> list[str]:
    """List files and directories under a repository-relative path."""
    if max_entries < 1:
        raise ValueError("max_entries must be >= 1")

    root = _resolve_repo_path(path)
    if not root.exists():
        raise FileNotFoundError(path)

    entries: list[str] = []

    def include_item(p: Path) -> bool:
        rel = p.relative_to(REPO_PATH)
        if include_hidden:
            return True
        return not any(part.startswith(".") for part in rel.parts)

    if root.is_file():
        if include_item(root):
            return [str(root.relative_to(REPO_PATH))]
        return []

    iterator = root.rglob("*") if recursive else root.glob("*")
    for item in iterator:
        if not include_item(item):
            continue
        rel = str(item.relative_to(REPO_PATH))
        if item.is_dir():
            rel += "/"
        entries.append(rel)
        if len(entries) >= max_entries:
            break

    entries.sort()
    return entries


@mcp.tool()
def read_file(
    path: str, encoding: str = "utf-8", max_bytes: int = MAX_READ_BYTES
) -> str:
    """Read a UTF-8 text file from the repository."""
    if max_bytes < 1:
        raise ValueError("max_bytes must be >= 1")

    file_path = _resolve_repo_path(path)
    if not file_path.is_file():
        raise FileNotFoundError(path)

    size = file_path.stat().st_size
    if size > max_bytes:
        raise ValueError(f"file is too large ({size} bytes > {max_bytes} bytes)")

    data = file_path.read_text(encoding=encoding)
    return _trim_text(data)


@mcp.tool()
def read_document(
    path: str,
    max_chars: int = 20000,
    max_pages: int = 20,
    max_rows_per_sheet: int = 200,
    output_profile: str | None = None,
) -> dict[str, Any]:
    """Read document formats: .pdf, .doc, .docx, .xls, .xlsx, .odt, .ods, .odp."""
    profile = _default_output_profile(output_profile)
    file_path = _resolve_repo_path(path)
    if not file_path.is_file():
        raise FileNotFoundError(path)
    ext = file_path.suffix.lower()
    if ext not in {".pdf", ".doc", ".docx", ".xls", ".xlsx", ".odt", ".ods", ".odp"}:
        raise ValueError(
            "unsupported extension; expected .pdf, .doc, .docx, .xls, .xlsx, .odt, .ods, or .odp"
        )

    warnings: list[str] = []
    metadata: dict[str, Any] = {"extension": ext}
    text = ""

    try:
        if ext == ".pdf":
            text, extra = _read_pdf_text(file_path, max_pages=max_pages)
        elif ext == ".docx":
            text, extra = _read_docx_text(file_path)
        elif ext == ".doc":
            text, extra = _read_doc_text(file_path)
            if extra.get("backend") != "antiword":
                warnings.append("antiword not available; used lossy latin-1 fallback for .doc")
        elif ext == ".xlsx":
            text, extra = _read_xlsx_text(file_path, max_rows_per_sheet=max_rows_per_sheet)
        elif ext in {".odt", ".ods", ".odp"}:
            text, extra = _read_opendoc_text(
                file_path,
                ext=ext,
                max_rows_per_sheet=max_rows_per_sheet,
            )
        else:
            text, extra = _read_xls_text(file_path, max_rows_per_sheet=max_rows_per_sheet)
    except Exception as exc:
        raise RuntimeError(f"failed to parse {ext} document: {exc}") from exc

    metadata.update(extra)
    text = text.strip()
    text, truncated = _truncate_with_flag(text, max_chars=max_chars)

    result = {
        "schema": "read_document.v1",
        "path": str(file_path.relative_to(REPO_PATH)),
        "extension": ext,
        "chars": len(text),
        "truncated": truncated,
        "warnings": warnings,
        "metadata": metadata if profile != "compact" else {},
        "text": text,
    }
    if profile == "compact":
        compact = {
            "schema": "read_document.compact.v1",
            "path": result["path"],
            "extension": ext,
            "chars": result["chars"],
            "truncated": truncated,
            "warnings": warnings,
            "text": text,
        }
        return _attach_untrusted_content_signals(
            compact, tool_name="read_document", text=text, input_scope="document_text"
        )
    return _attach_untrusted_content_signals(
        result, tool_name="read_document", text=text, input_scope="document_text"
    )


@mcp.tool()
def browse_web(
    url: str,
    timeout_seconds: int = 15,
    max_bytes: int = 300000,
    max_chars: int = 12000,
    extract_text: bool = True,
    output_profile: str | None = None,
) -> dict[str, Any]:
    """Fetch a web page/document over HTTP(S) using host/system certificate store."""
    if timeout_seconds < 1:
        raise ValueError("timeout_seconds must be >= 1")
    if max_bytes < 1:
        raise ValueError("max_bytes must be >= 1")
    if max_chars < 1:
        raise ValueError("max_chars must be >= 1")
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme.lower() not in {"http", "https"}:
        raise ValueError("url scheme must be http or https")

    profile = _default_output_profile(output_profile)
    req = urllib.request.Request(
        url,
        method="GET",
        headers={
            "User-Agent": "repo-git-mcp/1.0 (+browse_web)",
            "Accept": "text/html,application/xhtml+xml,application/xml,text/plain;q=0.9,*/*;q=0.8",
        },
    )
    try:
        with _urlopen_with_host_certs(req, timeout=timeout_seconds) as resp:
            status = int(getattr(resp, "status", 200))
            final_url = str(getattr(resp, "url", url))
            content_type = str(resp.headers.get("Content-Type", ""))
            raw = resp.read(max_bytes + 1)
    except urllib.error.URLError as exc:
        raise RuntimeError(f"browse failed: {exc}") from exc

    truncated_bytes = len(raw) > max_bytes
    if truncated_bytes:
        raw = raw[:max_bytes]
    charset_match = re.search(r"charset=([A-Za-z0-9._-]+)", content_type, flags=re.IGNORECASE)
    encoding = charset_match.group(1) if charset_match else "utf-8"
    text_raw = raw.decode(encoding, errors="replace")
    text = _html_to_text(text_raw) if extract_text else text_raw
    text, truncated_chars = _truncate_with_flag(text, max_chars=max_chars)

    result = {
        "schema": "browse_web.v1",
        "url": url,
        "final_url": final_url,
        "status": status,
        "content_type": content_type,
        "encoding": encoding,
        "extract_text": extract_text,
        "bytes_read": len(raw),
        "truncated_bytes": truncated_bytes,
        "truncated_chars": truncated_chars,
        "text": text,
    }
    if profile == "compact":
        compact = {
            "schema": "browse_web.compact.v1",
            "url": result["url"],
            "final_url": result["final_url"],
            "status": result["status"],
            "content_type": result["content_type"],
            "truncated": bool(truncated_bytes or truncated_chars),
            "text": result["text"],
        }
        return _attach_untrusted_content_signals(
            compact, tool_name="browse_web", text=text, input_scope="web_response_text"
        )
    return _attach_untrusted_content_signals(
        result, tool_name="browse_web", text=text, input_scope="web_response_text"
    )


@mcp.tool()
def interpret_presentation(
    path: str,
    max_slides: int = 50,
    max_chars_per_slide: int = 1200,
    use_local_model: bool = True,
    output_profile: str | None = None,
) -> dict[str, Any]:
    """Interpret presentation files (.pptx, .ppt, .odp) and optionally summarize with a local model."""
    profile = _default_output_profile(output_profile)
    file_path = _resolve_repo_path(path)
    if not file_path.is_file():
        raise FileNotFoundError(path)
    ext = file_path.suffix.lower()
    if ext not in {".pptx", ".ppt", ".odp"}:
        raise ValueError("unsupported extension; expected .pptx, .ppt, or .odp")

    warnings: list[str] = []
    if ext == ".pptx":
        slides, meta = _read_pptx_presentation(
            file_path, max_slides=max_slides, max_chars_per_slide=max_chars_per_slide
        )
    elif ext == ".odp":
        slides, meta = _read_odp_presentation(
            file_path, max_slides=max_slides, max_chars_per_slide=max_chars_per_slide
        )
    else:
        slides, meta, legacy_warnings = _read_ppt_legacy_text(
            file_path, max_slides=max_slides, max_chars_per_slide=max_chars_per_slide
        )
        warnings.extend(legacy_warnings)

    interpreted_summary = ""
    model_used = ""
    if use_local_model and slides:
        joined = "\n\n".join(
            f"Slide {s['index']} - {s['title']}\n{s['text']}" for s in slides[:12]
        )
        prompt = (
            "Summarize this presentation in <=8 bullets. "
            "Include objective, key points, risks, and action items.\n\n"
            f"{joined}"
        )
        try:
            inferred = local_infer(
                prompt=prompt,
                task="presentation_summary",
                backend="auto",
                output_profile="compact",
                max_tokens=400,
            )
            interpreted_summary = str(inferred.get("output", "")).strip()
            model_used = str(inferred.get("backend", ""))
        except Exception as exc:
            warnings.append(f"local model summary failed: {exc}")

    if not interpreted_summary:
        titles = [str(s.get("title", "")).strip() for s in slides if str(s.get("title", "")).strip()]
        if titles:
            interpreted_summary = "Slides cover: " + ", ".join(titles[:8])
            if len(titles) > 8:
                interpreted_summary += ", ..."
        else:
            interpreted_summary = "No textual content extracted from presentation."

    result = {
        "schema": "interpret_presentation.v1",
        "path": str(file_path.relative_to(REPO_PATH)),
        "extension": ext,
        "slide_count": int(meta.get("slide_count", len(slides))),
        "slides_read": int(meta.get("slides_read", len(slides))),
        "used_local_model": bool(model_used),
        "model_backend": model_used,
        "warnings": warnings,
        "summary": interpreted_summary,
        "slides": slides,
    }
    if profile == "compact":
        return {
            "schema": "interpret_presentation.compact.v1",
            "path": result["path"],
            "extension": ext,
            "slide_count": result["slide_count"],
            "slides_read": result["slides_read"],
            "used_local_model": result["used_local_model"],
            "warnings": warnings,
            "summary": interpreted_summary,
            "slides": [{"index": s["index"], "title": s["title"]} for s in slides[:50]],
        }
    return result


@mcp.tool()
def write_file(
    path: str,
    content: str,
    overwrite: bool = True,
    create_dirs: bool = True,
    encoding: str = "utf-8",
) -> dict[str, Any]:
    """Write a text file into the repository."""
    _require_mutations()
    file_path = _resolve_repo_path(path)

    if file_path.exists() and file_path.is_dir():
        raise IsADirectoryError(path)
    if file_path.exists() and not overwrite:
        raise FileExistsError(path)

    existed_before = file_path.exists()

    if create_dirs:
        file_path.parent.mkdir(parents=True, exist_ok=True)

    file_path.write_text(content, encoding=encoding)
    return {
        "path": str(file_path.relative_to(REPO_PATH)),
        "bytes_written": len(content.encode(encoding)),
        "existed_before": existed_before,
    }


@mcp.tool()
def delete_path(path: str, recursive: bool = False) -> dict[str, str]:
    """Delete a file or directory inside the repository."""
    _require_mutations()
    target = _resolve_repo_path(path)
    if not target.exists():
        raise FileNotFoundError(path)

    rel = str(target.relative_to(REPO_PATH))
    if target.is_dir():
        if recursive:
            shutil.rmtree(target)
        else:
            target.rmdir()
    else:
        target.unlink()
    return {"deleted": rel}


@mcp.tool()
def move_path(
    source: str,
    destination: str,
    overwrite: bool = False,
    create_dirs: bool = True,
) -> dict[str, str]:
    """Move or rename a file or directory inside the repository."""
    _require_mutations()
    src = _resolve_repo_path(source)
    dst = _resolve_repo_path(destination)

    if not src.exists():
        raise FileNotFoundError(source)
    if dst.exists() and not overwrite:
        raise FileExistsError(destination)
    if create_dirs:
        dst.parent.mkdir(parents=True, exist_ok=True)
    if dst.exists() and overwrite:
        if dst.is_dir():
            shutil.rmtree(dst)
        else:
            dst.unlink()

    shutil.move(str(src), str(dst))
    return {
        "source": str(src.relative_to(REPO_PATH)),
        "destination": str(dst.relative_to(REPO_PATH)),
    }


@mcp.tool()
def git_status(short: bool = True) -> dict[str, Any]:
    """Return git status as structured content with raw text preserved."""
    _require_git_repo()
    args = ["status"]
    if short:
        args.append("--short")
    raw = _trim_text(_git(*args).stdout)
    return {
        "status": [line for line in raw.splitlines() if line],
        "short": short,
        "raw": raw,
    }


@mcp.tool()
def git_diff(
    ref: str | None = None,
    pathspec: str | None = None,
    staged: bool = False,
) -> str:
    """Return a git diff against the working tree, index, or a ref."""
    _require_git_repo()
    args = ["diff"]
    if staged:
        args.append("--staged")
    if ref:
        args.append(ref)
    if pathspec:
        _resolve_repo_path(pathspec)
        args.extend(["--", pathspec])
    return _trim_text(_git(*args).stdout)


