def _prune_public_mcp_surface() -> None:
    for name in sorted(_declared_tool_names()):
        if name in PUBLIC_MCP_TOOL_NAMES:
            continue
        try:
            mcp.remove_tool(name)
        except Exception:
            continue


def _attach_release_readiness_app_metadata(tool: Any) -> None:
    if not _mcp_apps_dashboard_enabled():
        return
    ui_meta = {
        "resourceUri": RELEASE_READINESS_DASHBOARD_RESOURCE_URI,
        "visibility": ["model"],
    }
    existing = getattr(tool, "_meta", None)
    if not isinstance(existing, dict):
        existing = {}
    existing.setdefault("ui", ui_meta)
    tool.__dict__["_meta"] = existing
    tool.__dict__.setdefault("meta", existing)


def _mcp_client_compatible_output_schema(tool_name: str, schema: dict[str, Any]) -> dict[str, Any]:
    """Return an MCP-advertised outputSchema accepted by object-root clients.

    Some existing public tools intentionally return bare lists for Python and
    legacy MCP callers. Continue validates every advertised outputSchema root as
    an object, so preserve the precise legacy schema under an extension key while
    advertising an object-root compatibility schema for tools/list.
    """
    if schema.get("type") == "object":
        return schema
    return {
        "type": "object",
        "additionalProperties": True,
        "properties": {
            "result": schema,
        },
        "x-codebase-tooling-mcp-legacy-output-schema": schema,
        "description": f"{tool_name} returns the legacy payload directly; object root is advertised for MCP client compatibility.",
    }


def _apply_output_schemas_to_mcp_tools() -> None:
    """Attach checked-in outputSchema metadata to schema-backed FastMCP tools."""
    for name, schema in OUTPUT_SCHEMA_BY_TOOL.items():
        tool = mcp._tool_manager.get_tool(name)  # FastMCP has no public setter for outputSchema.
        if tool is None:
            continue
        tool.fn_metadata.output_schema = _mcp_client_compatible_output_schema(name, schema)
        tool.fn_metadata.output_model = _AnyToolOutput
        tool.fn_metadata.wrap_output = False
        tool.__dict__.pop("output_schema", None)
        if name == "release_readiness":
            _attach_release_readiness_app_metadata(tool)


_apply_output_schemas_to_mcp_tools()
_prune_public_mcp_surface()


def _agent_proxy_status_payload() -> dict[str, Any]:
    config = _agent_proxy_effective_config()
    return {
        "schema": "mcp_agent_proxy.status.v1",
        "enabled": bool(config.get("enabled")),
        "endpoint": "/v1/chat/completions",
        "policy_version": MCP_AGENT_PROXY_POLICY_VERSION,
        "anonymization_profile": MCP_AGENT_PROXY_ANONYMIZATION_PROFILE,
        "agent_facade_profile": MCP_AGENT_PROXY_AGENT_FACADE_PROFILE,
        "disabled_by_default": True,
        "explicit_proxy_only": True,
        "hidden_mitm_tls_interception": False,
        "credential_capture": False,
        "routing_controls": {
            "config_file": str(config.get("config_file", MCP_AGENT_PROXY_CONFIG_FILE)),
            "config_exists": bool(config.get("config_exists")),
            "config_source": "yaml" if config.get("config_exists") else "environment",
            "allow_online": bool(config.get("allow_online")),
            "no_network": bool(config.get("no_network"))
            or _agent_proxy_execution_mode_offline(),
            "prefer_local": bool(config.get("prefer_local")),
            "local_models": list(config.get("local_models", [])),
            "model_allowlist": list(config.get("model_allowlist", [])),
            "default_model": str(config.get("model", config.get("default_model", "model-fallback"))),
            "provider": str(config.get("provider", config.get("provider_name", "model-fallback"))),
            "model": str(config.get("model", config.get("default_model", "model-fallback"))),
            "apiBase_configured": bool(str(config.get("apiBase", config.get("provider_base_url", "")) or "").strip()),
            "apiType": str(config.get("apiType", "") or ""),
            "apiVersion_configured": bool(str(config.get("apiVersion", "") or "").strip()),
            "api_key_secret_state": _agent_proxy_secret_state(config),
            "provider_configured": bool(_agent_proxy_provider_url(config)),
            "timeout_seconds": MCP_AGENT_PROXY_TIMEOUT_SECONDS,
            "max_input_tokens": MCP_AGENT_PROXY_MAX_INPUT_TOKENS,
            "max_output_tokens": MCP_AGENT_PROXY_MAX_OUTPUT_TOKENS,
            "max_cost_usd": MCP_AGENT_PROXY_MAX_COST_USD,
        },
        "privacy_controls": {
            "strict_disclosure_audit": MCP_AGENT_PROXY_STRICT_DISCLOSURE_AUDIT,
            "anonymize_configured_terms": bool(_agent_proxy_configured_terms()),
            "irreversible_secret_redaction": True,
            "local_only_placeholder_mapping": True,
            "raw_prompt_storage_default": False,
            "raw_response_storage_default": False,
        },
        "memory_controls": {
            "capture_enabled": MCP_AGENT_PROXY_MEMORY_CAPTURE_ENABLED,
            "requires_mutations": MCP_AGENT_PROXY_MEMORY_CAPTURE_REQUIRE_MUTATIONS,
            "raw_conversation_storage": False,
        },
    }


async def agent_proxy_status(_request):
    return JSONResponse(_agent_proxy_status_payload())


async def agent_proxy_disclosures(request):
    filters = {
        "trace_id": request.query_params.get("trace_id", "").strip(),
        "since": request.query_params.get("since", "").strip(),
        "until": request.query_params.get("until", "").strip(),
    }
    return JSONResponse(_agent_proxy_disclosure_summary(filters))


async def openai_chat_completions(request):
    trace_id = uuid.uuid4().hex[:16]
    config = _agent_proxy_effective_config()
    if not bool(config.get("enabled")):
        _append_audit_event(
            "agent_proxy_request",
            ["network"],
            False,
            {"trace_id": trace_id, "path": "/v1/chat/completions"},
            "agent proxy disabled",
        )
        payload, status = _agent_proxy_error_payload(
            "agent proxy is disabled; set MCP_AGENT_PROXY_ENABLED=true and configure clients with this base_url",
            error_type="invalid_request_error",
            code="agent_proxy_disabled",
            trace_id=trace_id,
            status_code=404,
        )
        return JSONResponse(payload, status_code=status)

    try:
        payload = await request.json()
    except Exception:
        error, status = _agent_proxy_error_payload(
            "request body must be valid JSON",
            code="invalid_json",
            trace_id=trace_id,
            status_code=400,
        )
        return JSONResponse(error, status_code=status)

    valid, reason = _agent_proxy_validate_payload(payload)
    if not valid:
        error, status = _agent_proxy_error_payload(reason, trace_id=trace_id, status_code=400)
        return JSONResponse(error, status_code=status)

    policy_ok, policy_reason, policy = _agent_proxy_policy_limits(payload)
    if not policy_ok:
        _append_audit_event(
            "agent_proxy_policy",
            ["network", "audit"],
            False,
            {"trace_id": trace_id, "model": str(payload.get("model", ""))},
            policy_reason,
        )
        error, status = _agent_proxy_error_payload(
            policy_reason,
            error_type="invalid_request_error",
            code="agent_proxy_policy_denied",
            trace_id=trace_id,
            status_code=403,
        )
        return JSONResponse(error, status_code=status)

    route = _agent_proxy_route(payload)
    stream = bool(payload.get("stream", False))
    if route.get("backend") == "blocked":
        _append_audit_event(
            "agent_proxy_route",
            ["network", "audit"],
            False,
            {"trace_id": trace_id, "model": str(payload.get("model", "")), "reason": route.get("reason")},
            str(route.get("reason", "route blocked")),
        )
        status_code = 503 if route.get("reason") == "provider_url_not_configured" else 403
        error, status = _agent_proxy_error_payload(
            f"agent proxy route blocked: {route.get('reason')}",
            error_type="invalid_request_error",
            code="agent_proxy_route_blocked",
            trace_id=trace_id,
            status_code=status_code,
        )
        return JSONResponse(error, status_code=status)

    if route.get("backend") == "local":
        content = _agent_proxy_local_content(payload, route)
        response_payload = _agent_proxy_openai_response(payload, content, trace_id, route, policy)
        memory = _agent_proxy_memory_capture(trace_id, payload, response_payload, route, policy)
        response_payload["agent_proxy"] = _agent_proxy_metadata(trace_id, route, policy, None, memory)
        _append_audit_event(
            "agent_proxy_request",
            ["network"],
            True,
            {"trace_id": trace_id, "backend": "local", "model": str(payload.get("model", ""))},
            "local route selected",
        )
        if stream:
            return StreamingResponse(
                _agent_proxy_local_stream(payload, trace_id, route, policy, memory, request),
                media_type="text/event-stream",
                headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
            )
        return JSONResponse(response_payload)

    anonymized_payload, mapping = _agent_proxy_anonymize_payload(payload)
    provider_url = _agent_proxy_provider_url()
    try:
        _agent_proxy_record_online_request_audit(
            trace_id, payload, anonymized_payload, route, policy, mapping
        )
    except OSError:
        _append_audit_event(
            "agent_proxy_disclosure_audit",
            ["network", "audit"],
            False,
            {"trace_id": trace_id, "model": str(payload.get("model", ""))},
            "disclosure audit write failed; online provider call blocked",
        )
        error, status = _agent_proxy_error_payload(
            "disclosure audit could not be written; online provider call blocked",
            error_type="server_error",
            code="agent_proxy_disclosure_audit_failed",
            trace_id=trace_id,
            status_code=503,
        )
        return JSONResponse(error, status_code=status)

    if stream:
        return StreamingResponse(
            _agent_proxy_online_stream(
                payload, anonymized_payload, trace_id, route, policy, mapping, request
            ),
            media_type="text/event-stream",
            headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
        )

    try:
        provider_response = _agent_proxy_http_post_json(
            provider_url, anonymized_payload, MCP_AGENT_PROXY_TIMEOUT_SECONDS
        )
    except Exception:
        _agent_proxy_record_online_response_audit(
            trace_id,
            payload,
            anonymized_payload,
            route,
            policy,
            mapping,
            {"error": "provider request failed"},
            memory={"captured": False, "reason": "provider_request_failed"},
            success=False,
            reason="provider request failed",
        )
        error, status = _agent_proxy_error_payload(
            "online provider request failed",
            error_type="server_error",
            code="agent_proxy_provider_failed",
            trace_id=trace_id,
            status_code=502,
        )
        return JSONResponse(error, status_code=status)

    safe_response = _agent_proxy_deanonymize_value(provider_response, mapping)
    memory = _agent_proxy_memory_capture(trace_id, anonymized_payload, provider_response, route, policy)
    if isinstance(safe_response, dict):
        safe_response.setdefault("id", f"chatcmpl-proxy-{trace_id}")
        safe_response.setdefault("object", "chat.completion")
        safe_response.setdefault("created", int(time.time()))
        safe_response.setdefault("model", str(payload.get("model", "")))
        safe_response["agent_proxy"] = _agent_proxy_metadata(trace_id, route, policy, mapping, memory)
    _agent_proxy_record_online_response_audit(
        trace_id,
        payload,
        anonymized_payload,
        route,
        policy,
        mapping,
        safe_response,
        memory=memory,
    )
    return JSONResponse(safe_response)




def _continue_model_yaml(
    *,
    name: str,
    display_name: str,
    provider: str,
    model: str,
    api_base: str,
    roles: list[str] | None = None,
    proxy: str = "",
    ca_bundle_path: str = "",
    api_key_ref: str = "",
    timeout: int = 300000,
) -> str:
    role_items = roles or ["chat", "edit", "apply"]
    lines = [
        f"name: {name}",
        "version: 0.0.1",
        "schema: v1",
        "models:",
        f"  - name: {display_name}",
        f"    provider: {provider}",
        f"    model: {model}",
        f"    apiBase: {api_base}",
        *([f"    apiKey: {api_key_ref}"] if api_key_ref else []),
        "    roles:",
    ]
    lines.extend(f"      - {role}" for role in role_items)
    lines.extend(["    requestOptions:", f"      timeout: {timeout}"])
    if proxy:
        lines.append(f"      proxy: {proxy}")
    if ca_bundle_path:
        lines.append(f"      caBundlePath: {ca_bundle_path}")
    return "\n".join(lines) + "\n"


def _continue_model_routing_yaml(model: str, model_file: str) -> str:
    return f"""schema: v1
router:
  model: {model}
  file: {model_file}
routes:
  coding:
    model: {model}
    file: {model_file}
  coding_agent:
    model: {model}
    file: {model_file}
  coding_micro:
    model: qwen2.5-coder:1.5b
    file: .continue/models/coding-qwen2.5-coder-1.5b.yaml
"""


def _agent_proxy_runtime_config_payload(config: dict[str, str]) -> dict[str, Any]:
    provider = config.get("provider", "model-fallback") or "model-fallback"
    model = config.get("model", "model-fallback") or "model-fallback"
    api_key_ref = config.get("api_key_ref", "")
    requires_key = _agent_proxy_provider_requires_api_key(
        {"provider": provider, "apiType": config.get("api_type", "") or provider}
    )
    has_required_secret = (not requires_key) or _agent_proxy_config_has_usable_api_key(
        {**config, "apiKey": api_key_ref}
    )
    ready_for_online = (
        provider != "model-fallback"
        and model != "model-fallback"
        and bool(config.get("api_base", ""))
        and has_required_secret
    )
    return {
        "agent_proxy": {
            "enabled": True,
            "allow_online": bool(ready_for_online),
            "provider": provider if ready_for_online else "model-fallback",
            "model": model if ready_for_online else "model-fallback",
            "apiBase": config.get("api_base", "") if ready_for_online else "",
            "apiType": config.get("api_type", ""),
            "apiVersion": config.get("api_version", ""),
            "apiKey": api_key_ref if ready_for_online else "",
        }
    }

def _agent_proxy_runtime_config_yaml(config: dict[str, str]) -> str:
    payload = _agent_proxy_runtime_config_payload(config)
    header = (
        "# Local runtime config for codebase-tooling-mcp agent proxy.\n"
        "# Do not store API keys here; keep credentials in environment variables or Continue secrets.\n"
    )
    if yaml is not None:
        return header + yaml.safe_dump(payload, sort_keys=False)
    return header + json.dumps(payload, indent=2) + "\n"


def _continue_load_yaml_mapping(path: Path) -> dict[str, Any]:
    if not path.is_file() or yaml is None:
        return {}
    try:
        loaded = yaml.safe_load(path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    return loaded if isinstance(loaded, dict) else {}


def _continue_relative_path(path: Path) -> str:
    try:
        return str(path.relative_to(REPO_PATH))
    except ValueError:
        return str(path)


def _continue_default_root() -> Path:
    return Path(__file__).resolve().parent / "defaults" / "continue"


def _continue_model_profile_summary(path: Path, source: str = "repo") -> dict[str, str]:
    rel_path = _continue_relative_path(path)
    profile = _continue_load_yaml_mapping(path)
    models = profile.get("models") if isinstance(profile, dict) else None
    first_model = (
        models[0]
        if isinstance(models, list) and models and isinstance(models[0], dict)
        else {}
    )
    model = str(first_model.get("model", "") or "").strip()
    display_name = str(
        first_model.get("name", profile.get("name", "")) or ""
    ).strip()
    provider = str(first_model.get("provider", "") or "").strip().lower()
    api_base = str(
        first_model.get("apiBase", first_model.get("api_base", "")) or ""
    ).strip()
    return {
        "file": rel_path,
        "name": display_name,
        "provider": provider,
        "model": model,
        "apiBase": api_base,
        "source": source,
    }


def _continue_is_fallback_profile(profile: dict[str, str]) -> bool:
    return (
        profile.get("model") == "model-fallback"
        or profile.get("file") == ".continue/models/model-fallback.yaml"
        or "fallback" in profile.get("name", "").lower()
    )


def _continue_detected_default(
    routing: dict[str, Any], profiles: list[dict[str, str]]
) -> dict[str, str]:
    by_file = {profile.get("file", ""): profile for profile in profiles}
    by_model = {
        profile.get("model", ""): profile
        for profile in profiles
        if profile.get("model")
    }
    router = routing.get("router") if isinstance(routing.get("router"), dict) else {}
    route_model = str(router.get("model", "") or "").strip()
    route_file = str(router.get("file", "") or "").strip()
    for candidate in [by_file.get(route_file), by_model.get(route_model)]:
        if candidate and not _continue_is_fallback_profile(candidate):
            return {**candidate, "source": "model-routing.yaml"}
    for profile in profiles:
        if profile.get("provider") == "ollama" and not _continue_is_fallback_profile(
            profile
        ):
            return {**profile, "source": "local Ollama profile"}
    for profile in profiles:
        if not _continue_is_fallback_profile(profile):
            return {**profile, "source": "model profile"}
    return {}


def _continue_mcp_server_summary(path: Path, source: str = "repo") -> dict[str, Any]:
    config = _continue_load_yaml_mapping(path)
    servers = config.get("mcpServers") if isinstance(config, dict) else None
    first_server = (
        servers[0]
        if isinstance(servers, list) and servers and isinstance(servers[0], dict)
        else {}
    )
    request_options = first_server.get("requestOptions") if isinstance(first_server, dict) else {}
    headers = request_options.get("headers") if isinstance(request_options, dict) else {}
    authorization = str(headers.get("Authorization", "") or "").strip()
    return {
        "file": _continue_relative_path(path),
        "source": source,
        "name": str(first_server.get("name", config.get("name", "")) or "").strip(),
        "type": str(first_server.get("type", "") or "").strip(),
        "url": str(first_server.get("url", "") or "").strip(),
        "authorization_header_configured": bool(authorization),
        "uses_mcp_http_bearer_token_secret": "MCP_HTTP_BEARER_TOKEN" in authorization,
    }


def _continue_model_fallback_status() -> dict[str, Any]:
    continue_dir = REPO_PATH / ".continue"
    routing_path = continue_dir / "model-routing.yaml"
    models_dir = continue_dir / "models"
    default_root = _continue_default_root()
    default_models_dir = default_root / "models"
    model_paths = sorted(models_dir.glob("*.yaml")) if models_dir.is_dir() else []
    default_model_paths = (
        sorted(default_models_dir.glob("*.yaml")) if default_models_dir.is_dir() else []
    )
    routing = _continue_load_yaml_mapping(routing_path)
    default_routing = _continue_load_yaml_mapping(default_root / "model-routing.yaml")
    active_routing = routing if routing else default_routing
    router = active_routing.get("router") if isinstance(active_routing.get("router"), dict) else {}
    profiles = [_continue_model_profile_summary(path, "repo") for path in model_paths]
    default_profiles = [
        _continue_model_profile_summary(path, "bundled_default")
        for path in default_model_paths
    ]
    local_profiles = [
        profile
        for profile in profiles
        if profile.get("provider") == "ollama" and not _continue_is_fallback_profile(
            profile
        )
    ]
    detected_default = _continue_detected_default(routing, profiles)
    if not detected_default:
        detected_default = _continue_detected_default(default_routing, default_profiles)
        if detected_default:
            detected_default = {
                **detected_default,
                "source": f"bundled Continue default ({detected_default.get('source', 'model profile')})",
            }
    repo_mcp_paths = sorted((continue_dir / "mcpServers").glob("*.yaml")) if (continue_dir / "mcpServers").is_dir() else []
    default_mcp_paths = [default_root / "codebase-tooling-mcp.yaml"]
    mcp_servers = [
        _continue_mcp_server_summary(path, "repo") for path in repo_mcp_paths
    ] + [
        _continue_mcp_server_summary(path, "bundled_default")
        for path in default_mcp_paths
        if path.is_file()
    ]
    return {
        "schema": "continue_model_fallback.status.v1",
        "repo_path": str(REPO_PATH),
        "allow_mutations": ALLOW_MUTATIONS,
        "continue_dir_exists": continue_dir.is_dir(),
        "routing_exists": routing_path.is_file(),
        "model_profiles": [_continue_relative_path(path) for path in model_paths],
        "default_model_profiles": [_continue_relative_path(path) for path in default_model_paths],
        "routing": {
            "model": str(router.get("model", "") or ""),
            "file": str(router.get("file", "") or ""),
            "source": "repo" if routing else "bundled_default" if default_routing else "missing",
        },
        "profiles": profiles,
        "default_profiles": default_profiles,
        "local_profiles": local_profiles,
        "mcp_servers": mcp_servers,
        "detected_default": detected_default,
        "configure_endpoint": "/v1/model-fallback/configure",
    }


def _continue_model_fallback_user_text(payload: dict[str, Any]) -> str:
    messages = payload.get("messages", [])
    if not isinstance(messages, list):
        return ""
    parts: list[str] = []
    for message in messages:
        if not isinstance(message, dict) or message.get("role") != "user":
            continue
        content = message.get("content", "")
        if isinstance(content, str):
            parts.append(content)
        elif isinstance(content, list):
            for item in content:
                if isinstance(item, dict) and item.get("type") == "text":
                    parts.append(str(item.get("text", "")))
    return "\n".join(parts).lower()


def _continue_model_fallback_content(
    status: dict[str, Any], payload: dict[str, Any]
) -> str:
    detected_default = (
        status.get("detected_default")
        if isinstance(status.get("detected_default"), dict)
        else {}
    )
    user_text = _continue_model_fallback_user_text(payload)
    messages = payload.get("messages", [])
    user_request_count = (
        sum(
            1
            for message in messages
            if isinstance(message, dict) and message.get("role") == "user"
        )
        if isinstance(messages, list)
        else 0
    )
    if detected_default:
        default_label = " ".join(
            part
            for part in [
                str(detected_default.get("provider", "")).capitalize(),
                str(detected_default.get("model", "")),
            ]
            if part
        ).strip()
        found = (
            f"I found {detected_default.get('source', 'a Continue profile')} for "
            f"{default_label}, so I'll use that by default. You can change it later."
        )
        configure_hint = (
            f"When the token is ready, I can configure {detected_default.get('model')} "
            f"from {detected_default.get('file')}."
        )
    else:
        found = (
            "I did not find a real coding model profile yet, so I need the model "
            "details before Continue can code."
        )
        configure_hint = (
            'For a local OpenAI-compatible endpoint, use provider "openai", model, '
            "and apiBase."
        )
    mutation_note = (
        "I can write the config with /v1/model-fallback/configure."
        if ALLOW_MUTATIONS
        else "Mutations are off, so I can only show copy/paste config until ALLOW_MUTATIONS=true."
    )
    token_handled = any(
        marker in user_text
        for marker in ["skip", "mcp_http_bearer_token", "bearer", "token"]
    )
    if user_request_count >= 5:
        next_step = (
            "I won't ask more setup questions. Set the MCP_HTTP_BEARER_TOKEN secret, "
            "then use the detected default or send model details to /v1/model-fallback/configure."
        )
    elif not token_handled:
        next_step = (
            "First, paste the MCP token for Continue's MCP_HTTP_BEARER_TOKEN "
            "secret, or type skip."
        )
    elif detected_default:
        next_step = (
            f"Next, reply use default to keep {detected_default.get('model')}, "
            "or send a different model and endpoint."
        )
    else:
        next_step = "Next, send the provider, model, and apiBase you want Continue to use."
    return "\n".join(
        [
            "I can set up Continue. I am not the real coding model yet.",
            found,
            next_step,
            configure_hint,
            mutation_note,
        ]
    )


def _continue_model_fallback_stream(
    payload: dict[str, Any],
    content: str,
    trace_id: str,
    route: dict[str, Any],
    policy: dict[str, Any],
    status_payload: dict[str, Any],
    request: Any,
):
    async def _stream():
        yield _agent_proxy_sse_data(
            {
                **_agent_proxy_stream_chunk(payload, trace_id, {"role": "assistant"}),
                "agent_proxy": _agent_proxy_metadata(trace_id, route, policy),
                "model_fallback": status_payload,
            }
        )
        for part in content.split(" "):
            if await request.is_disconnected():
                return
            yield _agent_proxy_sse_data(
                _agent_proxy_stream_chunk(payload, trace_id, {"content": part + " "})
            )
            await asyncio.sleep(0)
        yield _agent_proxy_sse_data(_agent_proxy_stream_chunk(payload, trace_id, {}, "stop"))
        yield _agent_proxy_sse_data("[DONE]")

    return _stream()


def _continue_secret_ref(name: str) -> str:
    return "${{ secrets." + name + " }}"


def _continue_default_api_key_secret_name(provider: str) -> str:
    normalized = re.sub(r"[^A-Za-z0-9]+", "_", provider.upper()).strip("_") or "AGENT_PROXY"
    if normalized in {"OPENAI", "AZURE"}:
        return f"{normalized}_API_KEY"
    return f"{normalized}_AGENT_PROXY_API_KEY"


def _continue_model_config_payload(payload: dict[str, Any]) -> tuple[dict[str, str] | None, str]:
    provider = str(payload.get("provider", "model-fallback")).strip().lower()
    model = str(payload.get("model", "model-fallback")).strip()
    api_base = str(payload.get("apiBase", payload.get("api_base", ""))).strip()
    api_type = str(payload.get("apiType", payload.get("api_type", ""))).strip().lower()
    api_version = str(payload.get("apiVersion", payload.get("api_version", ""))).strip()
    api_key = str(payload.get("apiKey", payload.get("api_key", ""))).strip()
    api_key_secret_name = str(
        payload.get("apiKeySecretName", payload.get("api_key_secret_name", ""))
    ).strip()
    api_key_ref = str(payload.get("apiKeyRef", payload.get("api_key_ref", ""))).strip()
    proxy = str(payload.get("proxy", "")).strip()
    ca_bundle_path = str(payload.get("caBundlePath", payload.get("ca_bundle_path", ""))).strip()
    if not re.fullmatch(r"[a-z0-9][a-z0-9._-]*", provider):
        return None, "provider must be a non-empty provider id such as azure, openai, ollama, or model-fallback"
    if not model:
        return None, "model is required"
    if provider != "model-fallback" and not api_base:
        return None, "apiBase is required"
    if api_base and not urllib.parse.urlsplit(api_base).scheme:
        return None, "apiBase must be an absolute URL"
    if proxy and not urllib.parse.urlsplit(proxy).scheme:
        return None, "proxy must be an absolute URL when provided"
    requires_key = _agent_proxy_provider_requires_api_key(
        {"provider": provider, "apiType": api_type or provider}
    )
    if requires_key:
        if api_key_secret_name and not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", api_key_secret_name):
            return None, "apiKeySecretName must be an environment-style name"
        if not api_key_ref:
            api_key_secret_name = api_key_secret_name or _continue_default_api_key_secret_name(provider)
            api_key_ref = _continue_secret_ref(api_key_secret_name)
        if not _agent_proxy_secret_name_from_ref(api_key_ref):
            return None, "apiKeyRef must be a Continue secret reference such as ${{ secrets.AZURE_API_KEY }}"
    elif api_key and not api_key_ref:
        api_key_secret_name = api_key_secret_name or _continue_default_api_key_secret_name(provider)
        api_key_ref = _continue_secret_ref(api_key_secret_name)
    secret_name = _agent_proxy_secret_name_from_ref(api_key_ref)
    needs_secret = bool(
        requires_key and not api_key and not _agent_proxy_resolve_secret_ref(api_key_ref)
    )
    return {
        "provider": provider,
        "model": model,
        "api_base": api_base,
        "api_type": api_type,
        "api_version": api_version,
        "api_key": api_key,
        "api_key_ref": api_key_ref,
        "api_key_secret_name": secret_name,
        "requires_api_key": "true" if requires_key else "false",
        "needs_secret": "true" if needs_secret else "false",
        "proxy": proxy,
        "ca_bundle_path": ca_bundle_path,
    }, "needs-secret" if needs_secret else "ok"


def _continue_upsert_secret(name: str, value: str) -> bool:
    if not name or not value:
        return False
    env_path = REPO_PATH / ".continue/.env"
    env_path.parent.mkdir(parents=True, exist_ok=True)
    existing = env_path.read_text(encoding="utf-8").splitlines() if env_path.is_file() else []
    updated = False
    lines: list[str] = []
    for line in existing:
        if line.startswith(f"{name}="):
            lines.append(f"{name}={value}")
            updated = True
        else:
            lines.append(line)
    if not updated:
        lines.append(f"{name}={value}")
    env_path.write_text("\n".join(lines).rstrip("\n") + "\n", encoding="utf-8")
    try:
        env_path.chmod(0o600)
        env_path.parent.chmod(0o700)
    except OSError:
        pass
    return True



async def continue_model_fallback_chat_completions(request):
    trace_id = uuid.uuid4().hex[:16]
    try:
        payload = await request.json()
    except Exception:
        error, status = _agent_proxy_error_payload(
            "request body must be valid JSON",
            code="invalid_json",
            trace_id=trace_id,
            status_code=400,
        )
        return JSONResponse(error, status_code=status)
    valid, reason = _agent_proxy_validate_payload(payload)
    if not valid:
        error, status = _agent_proxy_error_payload(reason, trace_id=trace_id, status_code=400)
        return JSONResponse(error, status_code=status)
    status_payload = _continue_model_fallback_status()
    content = _continue_model_fallback_content(status_payload, payload)
    route = {
        "schema": "continue_model_fallback.routing.v1",
        "requested_model": str(payload.get("model", "model-fallback")),
        "backend": "model-fallback",
        "provider": "local-configuration-assistant",
        "reason": "continue_model_configuration_assistance",
        "risk_class": "repo_bound_configuration",
    }
    policy = {"input_tokens_estimate": _agent_proxy_estimate_tokens(_agent_proxy_request_text_digest_input(payload))}
    if bool(payload.get("stream", False)):
        return StreamingResponse(
            _continue_model_fallback_stream(
                payload, content, trace_id, route, policy, status_payload, request
            ),
            media_type="text/event-stream",
            headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
        )
    response_payload = _agent_proxy_openai_response(payload, content, trace_id, route, policy)
    response_payload["model_fallback"] = status_payload
    return JSONResponse(response_payload)


def _continue_model_configure_sections(
    *, status: str, reason: str, summary: dict[str, Any]
) -> dict[str, Any]:
    changes = summary.get("changes", [])
    rendered_changes = [
        f"{item.get('action', 'change')} {item.get('path', '')}".strip()
        for item in changes
        if isinstance(item, dict)
    ]
    provider = str(summary.get("provider", "model-fallback"))
    model = str(summary.get("model", "model-fallback"))
    api_base = str(summary.get("apiBase", ""))
    return {
        "status": {"value": status, "reason": reason},
        "config_path": str(summary.get("config_path", "")),
        "provider_model": {
            "provider": provider,
            "model": model,
            "apiBase_configured": bool(api_base),
            "apiType": str(summary.get("apiType", "")),
            "apiVersion_configured": bool(summary.get("apiVersion_configured")),
        },
        "secret": {"state": str(summary.get("secret_state", "not_required"))},
        "changes": rendered_changes,
        "next_step": str(summary.get("next_step", "")),
    }


async def continue_model_fallback_configure(request):
    try:
        payload = await request.json()
    except Exception:
        return JSONResponse({"error": "request body must be valid JSON"}, status_code=400)
    if not isinstance(payload, dict):
        return JSONResponse({"error": "request body must be a JSON object"}, status_code=400)
    config, reason = _continue_model_config_payload(payload)
    if config is None:
        return JSONResponse({"error": reason}, status_code=400)

    profile_rel = Path(".continue/models/coding-openai-compatible.yaml")
    routing_rel = Path(".continue/model-routing.yaml")
    secret_rel = Path(".continue/.env")
    agent_proxy_path = _agent_proxy_config_path()
    agent_proxy_rel = Path(_continue_relative_path(agent_proxy_path))
    display_provider = config["provider"]
    profile_text = _continue_model_yaml(
        name="coding-openai-compatible",
        display_name=f"Coding - {display_provider} Endpoint",
        provider="openai" if display_provider == "azure" else display_provider,
        model=config["model"],
        api_base=config["api_base"] or "http://localhost:8000/v1/model-fallback",
        proxy=config["proxy"],
        ca_bundle_path=config["ca_bundle_path"],
        api_key_ref=config["api_key_ref"],
    )
    routing_text = _continue_model_routing_yaml(
        config["model"], ".continue/models/coding-openai-compatible.yaml"
    )
    agent_proxy_text = _agent_proxy_runtime_config_yaml(config)
    files_for_gate = [str(profile_rel), str(routing_rel), str(agent_proxy_rel)]
    if config.get("api_key"):
        files_for_gate.append(str(secret_rel))
    _require_tool_security_gate(
        "continue_model_fallback_configure",
        {
            "mode": "write",
            "files": files_for_gate,
        },
        enforce_mutation_permission=False,
    )
    changes = [
        {"path": str(profile_rel), "action": "create_or_update_continue_model"},
        {"path": str(routing_rel), "action": "create_or_update_continue_routing"},
        {"path": str(agent_proxy_rel), "action": "create_or_update_runtime_yaml"},
    ]
    if config.get("api_key"):
        changes.append(
            {
                "path": str(secret_rel),
                "action": "store_continue_secret",
                "secret": config["api_key_secret_name"],
            }
        )
    if config.get("needs_secret") == "true":
        secret_state = "needs-secret"
        next_step = (
            f"Provide {config['api_key_secret_name']} through this mutation-gated configure "
            "flow as apiKey, or create that Continue secret before enabling online routing."
        )
    elif config.get("api_key"):
        secret_state = "will_store_continue_secret"
        next_step = "Restart/reload the client, then send chat completions through the configured model."
    else:
        secret_state = _agent_proxy_secret_state(
            _agent_proxy_runtime_config_payload(config)["agent_proxy"]
        )
        next_step = "Restart/reload the client, then send chat completions through the configured model."
    summary = {
        "config_path": str(agent_proxy_rel),
        "provider": config["provider"],
        "model": config["model"],
        "apiBase": config["api_base"],
        "apiType": config["api_type"],
        "apiVersion_configured": bool(config["api_version"]),
        "secret_state": secret_state,
        "changes": changes,
        "next_step": next_step,
    }
    if config.get("needs_secret") == "true":
        sections = _continue_model_configure_sections(
            status="needs-secret", reason=reason, summary=summary
        )
        return JSONResponse(
            {
                "schema": "continue_model_fallback.configure.v1",
                "status": "needs-secret",
                "reason": "provider requires an API key but no usable Continue secret is configured",
                "summary": summary,
                "sections": sections,
            },
            status_code=200,
        )
    if not ALLOW_MUTATIONS:
        sections = _continue_model_configure_sections(
            status="dry_run",
            reason="mutations disabled; set ALLOW_MUTATIONS=true to write files",
            summary=summary,
        )
        return JSONResponse(
            {
                "schema": "continue_model_fallback.configure.v1",
                "status": "dry_run",
                "reason": "mutations disabled; set ALLOW_MUTATIONS=true to write files",
                "summary": summary,
                "sections": sections,
                "files": {
                    str(profile_rel): profile_text,
                    str(routing_rel): routing_text,
                    str(agent_proxy_rel): agent_proxy_text,
                },
            },
            status_code=403,
        )

    profile_path = (REPO_PATH / profile_rel).resolve()
    routing_path = (REPO_PATH / routing_rel).resolve()
    secret_path = (REPO_PATH / secret_rel).resolve()
    profile_path.relative_to(REPO_PATH)
    routing_path.relative_to(REPO_PATH)
    secret_path.relative_to(REPO_PATH)
    agent_proxy_path.relative_to(REPO_PATH)
    profile_path.parent.mkdir(parents=True, exist_ok=True)
    routing_path.parent.mkdir(parents=True, exist_ok=True)
    agent_proxy_path.parent.mkdir(parents=True, exist_ok=True)
    profile_path.write_text(profile_text, encoding="utf-8")
    routing_path.write_text(routing_text, encoding="utf-8")
    agent_proxy_path.write_text(agent_proxy_text, encoding="utf-8")
    if config.get("api_key"):
        _continue_upsert_secret(config["api_key_secret_name"], config["api_key"])
    written_secret_state = _agent_proxy_secret_state(
        _agent_proxy_runtime_config_payload(config)["agent_proxy"]
    )
    written_summary = {**summary, "secret_state": written_secret_state}
    return JSONResponse(
        {
            "schema": "continue_model_fallback.configure.v1",
            "status": "written",
            "summary": written_summary,
            "sections": _continue_model_configure_sections(
                status="written", reason="configuration files written", summary=written_summary
            ),
            "files": [str(profile_rel), str(routing_rel), str(agent_proxy_rel)]
            + ([str(secret_rel)] if config.get("api_key") else []),
            "model": config["model"],
            "provider": config["provider"],
            "apiBase": config["api_base"],
            "secret_state": written_secret_state,
        }
    )


async def mcp_server_manifest(_request):
    return JSONResponse(_mcp_server_manifest_payload())


async def healthz(_request):
    runtime = _runtime_state_payload(include_ollama_probe=False)
    server_state = runtime.get("server", {})
    ollama_state = runtime.get("ollama", {})
    oauth_resource_config_error = _http_oauth_resource_config_error()
    scope_config_error = _http_bearer_token_scope_config_error()
    auth_configuration_error = oauth_resource_config_error or scope_config_error
    return JSONResponse(
        {
            "ok": True,
            "repo_path": str(REPO_PATH),
            "is_git_repo": _is_git_repo(),
            "allow_mutations": ALLOW_MUTATIONS,
            "transport": MCP_TRANSPORT,
            "runtime_image_version": runtime_image_version().rendered,
            "mcp_coding_experiment_version": mcp_coding_experiment_version().rendered,
            "server": {
                "http_mode": server_state.get("http_mode"),
                "port": server_state.get("port"),
                "port_listening": server_state.get("port_listening"),
            },
            "auth": {
                "mode": MCP_HTTP_AUTH_MODE,
                "oauth_resource_configured": MCP_HTTP_AUTH_MODE == "oauth-resource"
                and not bool(oauth_resource_config_error),
                "configuration_error": auth_configuration_error,
                "scope_configuration_error": scope_config_error,
                "scopes_supported": _supported_mcp_scopes(),
                "local_bearer_token_scopes": sorted(_local_bearer_token_granted_scopes()),
                "oauth_protected_resource_metadata": "/.well-known/oauth-protected-resource",
            },
            "ollama": {
                "running": ollama_state.get("running"),
                "serve_processes": ollama_state.get("serve_processes"),
                "configured_port": ollama_state.get("configured_port"),
                "configured_port_listening": ollama_state.get("configured_port_listening"),
                "port_11434_listening": ollama_state.get("port_11434_listening"),
            },
        }
    )


async def root(_request):
    return PlainTextResponse("git-repo-manager MCP server")


async def sse_events(request):
    raw_last = request.query_params.get("last", "20").strip()
    try:
        last = int(raw_last or "20")
    except ValueError:
        last = 20
    subscriber_id = uuid.uuid4().hex[:12]
    subscriber: queue.Queue[dict[str, Any]] = queue.Queue(maxsize=SSE_SUBSCRIBER_QUEUE_MAX)
    replay = _sse_replay(limit=last)
    with _SSE_LOCK:
        _SSE_SUBSCRIBERS[subscriber_id] = subscriber
    _sse_publish("sse.connected", subscriber_id=subscriber_id, replayed=len(replay))

    async def _event_stream():
        try:
            for entry in replay:
                yield _sse_encode_event(entry)
            while True:
                if await request.is_disconnected():
                    break
                try:
                    entry = subscriber.get_nowait()
                    yield _sse_encode_event(entry)
                except queue.Empty:
                    yield ": keepalive\n\n"
                    await asyncio.sleep(SSE_HEARTBEAT_SECONDS)
        finally:
            with _SSE_LOCK:
                _SSE_SUBSCRIBERS.pop(subscriber_id, None)
            _sse_publish("sse.disconnected", subscriber_id=subscriber_id)

    return StreamingResponse(
        _event_stream(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "Connection": "keep-alive",
            "X-Accel-Buffering": "no",
        },
    )


@contextlib.asynccontextmanager
async def lifespan(app: Starlette):
    async with mcp.session_manager.run():
        yield


starlette_app = Starlette(
    routes=[
        Route("/", root, methods=["GET"]),
        Route("/healthz", healthz, methods=["GET"]),
        Route("/.well-known/mcp-server.json", mcp_server_manifest, methods=["GET"]),
        Route("/sse", sse_events, methods=["GET"]),
        Route("/v1/chat/completions", openai_chat_completions, methods=["POST"]),
        Route("/v1/model-fallback/chat/completions", continue_model_fallback_chat_completions, methods=["POST"]),
        Route("/v1/model-fallback/configure", continue_model_fallback_configure, methods=["POST"]),
        Route("/v1/agent-proxy/status", agent_proxy_status, methods=["GET"]),
        Route("/v1/agent-proxy/disclosures", agent_proxy_disclosures, methods=["GET"]),
        # FastMCP's streamable HTTP app serves MCP routes under `/mcp` internally.
        # Mount at root so the public MCP endpoint is exactly `/mcp`.
        Mount("/", app=mcp.streamable_http_app()),
    ],
    lifespan=lifespan,
)

authenticated_starlette_app = MCPHTTPAuthMiddleware(starlette_app)

app = CORSMiddleware(
    authenticated_starlette_app,
    allow_origins=ALLOW_ORIGINS,
    allow_methods=["GET", "POST", "DELETE"],
    allow_headers=["*"],
    expose_headers=["Mcp-Session-Id"],
)


def main() -> None:
    transport = MCP_TRANSPORT

    if transport in {"stdio", "direct"}:
        mcp.run()
        return

    if transport in {"http", "streamable-http", "streamable_http"}:
        import uvicorn

        uvicorn.run(app, host=HOST, port=PORT)
        return

    raise ValueError(
        "Unsupported MCP_TRANSPORT. Expected one of: stdio, direct, http, streamable-http"
    )


if __name__ == "__main__":
    main()
